-- Flashcard topics & cards
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-war-fc-1', '1. Causes of War: Long-term, Short-term, and Immediate', '#C4A36A', 'P2-WAR', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-1', 'What are the different types of causes of war?', 'Long-term (structural conditions: alliances, nationalism, imperialism, militarism), short-term (specific crises, arms races, diplomatic failures), and immediate/trigger causes (specific events that precipitate conflict, e.g., assassination of Franz Ferdinand).', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-1', 'What is the M.A.I.N. framework for WWI causes?', 'Militarism (arms race, war plans), Alliances (Triple Alliance, Triple Entente), Imperialism (colonial rivalries), and Nationalism (ethnic tensions, Pan-Slavism). These long-term factors created a powder keg ignited by the Sarajevo assassination.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-1', 'What were the causes of WWII in Europe?', 'Treaty of Versailles resentment, failure of appeasement, Hitler''s aggressive foreign policy (remilitarisation, Anschluss, Sudetenland), failure of collective security (League of Nations weakness), Nazi-Soviet Pact, and economic factors (Great Depression).', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-1', 'What were the causes of WWII in the Pacific?', 'Japanese militarism and expansionism, desire for resources (oil, rubber), invasion of Manchuria (1931) and China (1937), US oil embargo (1941), failure of diplomatic negotiations, and Pearl Harbor (December 1941).', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-1', 'What is the difference between economic and ideological causes of war?', 'Economic: competition for resources, trade disputes, economic crises creating instability. Ideological: clash of political systems (fascism vs. democracy vs. communism), nationalism, racism, religious conflict. Most wars involve both.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-1', 'What role does leadership play in causing wars?', 'Individual leaders'' decisions, miscalculations, and ambitions can precipitate war: Hitler''s expansionism, Japanese militarists, Saddam Hussein''s invasion of Kuwait. However, structural factors constrain and enable leaders'' choices.', 6);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-war-fc-2', '2. Practices and Nature of 20th-Century Wars', '#C4A36A', 'P2-WAR', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-2', 'How did warfare change in the 20th century?', 'From limited conflicts to ''total war'': mass mobilisation of civilians, industrial warfare, new technology (tanks, aircraft, submarines, nuclear weapons), ideological motivation, targeting of civilians, and blurring of home front/front line distinction.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-2', 'What is total war?', 'A war in which a nation mobilises all its resources (economic, industrial, human) and targets both military and civilian populations. Distinction between combatants and non-combatants collapses. WWI and WWII are prime examples.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-2', 'How did technology change warfare?', 'WWI: machine guns, poison gas, tanks, aircraft, submarines. WWII: blitzkrieg, strategic bombing, aircraft carriers, radar, code-breaking, and atomic weapons. Each innovation changed tactical and strategic possibilities.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-2', 'What was guerrilla warfare''s role?', 'Irregular forces using hit-and-run tactics, ambushes, and local knowledge against conventional armies. Effective in colonial/independence wars (Vietnam, Algeria, Cuba) and resistance movements. Mao''s ''People''s War'' theory formalised it.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-2', 'What was the significance of air power?', 'Strategic bombing targeted industrial capacity and civilian morale (London Blitz, firebombing of Dresden/Tokyo). It culminated in atomic bombs on Hiroshima and Nagasaki (1945), fundamentally changing warfare and international relations.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-2', 'How were civilians affected by 20th-century wars?', 'Through bombing of cities, occupation, forced labour, genocide (Holocaust), displacement/refugees, rationing, propaganda mobilisation, sexual violence, and the draft. Civilian casualties often exceeded military casualties.', 6);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-war-fc-3', '3. WWI: The Great War (1914-1918)', '#C4A36A', 'P2-WAR', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-3', 'What were the key features of trench warfare?', 'Static defensive lines on the Western Front, no-man''s land, attrition strategy, massive casualties for minimal territorial gain, mud/disease/psychological trauma, and technological innovations to break the deadlock (gas, tanks, aircraft).', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-3', 'What was the Schlieffen Plan?', 'Germany''s strategy to avoid a two-front war by rapidly defeating France through Belgium before turning east against Russia. It failed at the Battle of the Marne (September 1914), leading to the trench warfare stalemate.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-3', 'What was the significance of Verdun and the Somme (1916)?', 'Both symbolise WWI''s horror: Verdun (German attrition attempt, ~700,000 casualties) and the Somme (British offensive, 57,000 British casualties on the first day, ~1 million total). Neither achieved decisive results.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-3', 'Why did Germany lose WWI?', 'US entry (1917), British naval blockade causing starvation, failure of Spring Offensive (1918), allied tank/combined arms advances, internal unrest (November Revolution), and exhaustion of German resources and manpower.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-3', 'What was the Treaty of Versailles (1919)?', 'Peace treaty imposed on Germany: war guilt clause (Article 231), reparations (132 billion gold marks), territorial losses (Alsace-Lorraine, colonies, Polish corridor), military restrictions (100,000 army, no air force), and loss of 13% of territory.', 5);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-war-fc-4', '4. WWII in Europe (1939-1945)', '#C4A36A', 'P2-WAR', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-4', 'What was blitzkrieg?', 'German ''lightning war'' strategy combining tanks, motorised infantry, and air support (Stuka dive bombers) for rapid breakthroughs. It conquered Poland (1939), France (1940), and initially succeeded in the USSR (1941) before failing due to overextension.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-4', 'Why did Germany invade the USSR (Operation Barbarossa)?', 'Ideological hatred of communism, desire for Lebensraum in the East, perceived racial inferiority of Slavs, desire for Soviet resources (oil, grain), and Hitler''s strategic gamble to eliminate the eastern threat before the US entered the war.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-4', 'What was the turning point of WWII in Europe?', 'Stalingrad (1942-43): German 6th Army was encircled and destroyed; 800,000+ Axis casualties. It ended German offensive capability in the East and marked the beginning of Soviet advance westward.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-4', 'What was D-Day (6 June 1944)?', 'Allied amphibious invasion of Normandy, France - the largest seaborne invasion in history. It opened a second front in Western Europe, liberating France and advancing toward Germany. Over 150,000 troops landed on the first day.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-4', 'What was the Holocaust?', 'The systematic, state-sponsored murder of 6 million Jews by Nazi Germany (1941-45), along with millions of Roma, disabled people, political opponents, homosexuals, and others. Methods included mass shootings (Einsatzgruppen), gas chambers (Auschwitz, Treblinka), and death marches.', 5);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-war-fc-5', '5. WWII in the Pacific (1941-1945)', '#C4A36A', 'P2-WAR', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-5', 'Why did Japan attack Pearl Harbor (7 Dec 1941)?', 'To destroy the US Pacific Fleet and buy time for expansion into resource-rich Southeast Asia (oil, rubber, tin). Japan calculated the US would negotiate rather than fight a long war. It was a tactical success but a strategic disaster (united American public for war).', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-5', 'What was island-hopping?', 'The US strategy of capturing strategically important islands while bypassing heavily fortified Japanese positions, moving progressively closer to Japan (Guadalcanal, Iwo Jima, Okinawa). It was costly but effective.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-5', 'Why were atomic bombs dropped on Japan?', 'To force Japanese surrender without a costly land invasion (estimated 250,000-1 million Allied casualties), demonstrate US power to the USSR, end the war quickly, and punish Japan. The decision remains deeply controversial.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-5', 'What was the impact of the atomic bombs?', 'Hiroshima (6 Aug) and Nagasaki (9 Aug) killed approximately 200,000+ people. Japan surrendered on 15 August 1945 (V-J Day). The bombs inaugurated the nuclear age, transforming international relations and sparking a nuclear arms race.', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-war-fc-6', '6. Effects of Wars: Political, Economic, Social', '#C4A36A', 'P2-WAR', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-6', 'What were the political effects of WWI?', 'Collapse of four empires (Russian, German, Austro-Hungarian, Ottoman), creation of new states (Poland, Czechoslovakia, Yugoslavia), rise of communism (Russian Revolution), League of Nations established, Treaty of Versailles resentment, and seeds of WWII.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-6', 'What were the political effects of WWII?', 'United Nations established (1945), decolonisation accelerated, Cold War began (US vs. USSR), Germany/Japan occupied and democratised, Eastern Europe came under Soviet control, Israel created (1948), and human rights frameworks developed (UN Declaration 1948).', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-6', 'What were the economic effects of major wars?', 'Destruction of infrastructure, debt accumulation, inflation, disruption of trade, but also: industrial mobilisation, technological innovation, women entering the workforce, post-war booms (e.g., 1950s-60s golden age), and Marshall Plan reconstruction.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-6', 'What were the social effects of wars?', 'Massive casualties (WWI: 17M, WWII: 70-85M), displacement/refugees, changed gender roles (women in workforce), psychological trauma (shell shock/PTSD), demographic changes, social mobility, and cultural shifts (disillusionment, modernism).', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-war-fc-7', '7. The Spanish Civil War (1936-1939)', '#C4A36A', 'P2-WAR', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'What caused the Spanish Civil War?', 'Political polarisation (left vs. right), failure of the Second Republic, military uprising led by Franco (July 1936), regional tensions (Catalonia, Basque Country), land reform disputes, Church-state conflict, and ideological extremism on both sides.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'What foreign intervention occurred?', 'Germany and Italy supported Franco (Condor Legion, weapons, troops). The USSR supported the Republic (weapons, advisors). International Brigades (volunteer fighters from many countries). Britain and France pursued non-intervention, effectively helping Franco.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'What was the significance of Guernica (1937)?', 'German Condor Legion bombed the Basque town of Guernica, killing hundreds of civilians. It became a symbol of fascist brutality and the horrors of modern aerial warfare. Picasso''s painting immortalised the atrocity.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-7', 'What was the outcome?', 'Franco''s Nationalists won in April 1939. Franco established a dictatorship lasting until his death in 1975. The war killed approximately 500,000 people and served as a rehearsal for WWII.', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-war-fc-8', '8. The Chinese Civil War (1927-1949)', '#C4A36A', 'P2-WAR', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-8', 'What caused the Chinese Civil War?', 'KMT-CCP ideological rivalry, failure of the First United Front (Shanghai Massacre 1927), warlordism, Japanese invasion (creating temporary Second United Front 1937-45), peasant grievances, and competition for post-WWII control of China.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-8', 'What was the Long March (1934-35)?', 'The CCP''s 6,000-mile retreat from KMT encirclement. Only 10% survived (~8,000 of 80,000). It preserved the Communist movement, established Mao''s leadership, built peasant support, and became a founding myth of the PRC.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-8', 'Why did the CCP win?', 'Peasant support (land reform promises), effective guerrilla warfare, KMT corruption and incompetence, KMT loss of popular support, CCP discipline, Soviet capture of Japanese weapons transferred to CCP, and US failure to effectively support KMT.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-8', 'What was the impact of the CCP victory?', 'PRC established (1 Oct 1949), KMT fled to Taiwan, radical social transformation (land reform, collectivisation), Cold War implications (communist ''loss'' of China shocked the US), and beginning of Sino-Soviet alliance.', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-war-fc-9', '9. The Korean War (1950-1953) and Vietnam War (1955-1975)', '#C4A36A', 'P2-WAR', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-9', 'What caused the Korean War?', 'Division of Korea at the 38th parallel (1945), Cold War rivalry, Kim Il-sung''s ambition to reunify Korea under communism, US containment policy, Chinese Revolution (1949) encouraging communist expansion, and miscalculations by both sides.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-9', 'What was the significance of the Korean War?', 'First ''hot war'' of the Cold War, demonstrated US commitment to containment, China proved itself a military power, Korea remained divided (still today), UN first military action, and it intensified the arms race and NATO commitment.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-9', 'What caused US involvement in Vietnam?', 'Cold War containment policy (domino theory), SEATO obligations, French defeat at Dien Bien Phu (1954), Gulf of Tonkin incident (1964), fear of communist expansion in Southeast Asia, and gradual escalation under Kennedy and Johnson.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-9', 'Why did the US fail in Vietnam?', 'Viet Cong guerrilla tactics, North Vietnamese determination, lack of popular support for South Vietnamese government, US public opposition (anti-war movement), media coverage, terrain difficulties, and inability to win ''hearts and minds''.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-war-fc-9', 'What was the Tet Offensive (1968)?', 'A massive surprise attack by North Vietnamese and Viet Cong forces during the Tet holiday. While a military failure for the communists, it was a psychological and political victory: it shattered US claims of winning and turned American public opinion against the war.', 5);

