-- Written questions (15 marks)
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-100', '1. Causes of War: Long-term, Short-term, and Immediate', 'SL/HL', 'short_answer', 'P2-WAR', 15, 'Compare and contrast the causes of two 20th-century wars.', '• Band 5 (13-15): Systematic comparison of long-term, short-term, and immediate causes with specific evidence from two wars.
• Examples: WWI (M.A.I.N. + assassination trigger) vs. WWII (Versailles legacy, appeasement failure, Hitler''s aggression, ideological clash).
• Or: WWII Pacific (Japanese expansionism, resource competition) vs. Korean War (Cold War ideology, division of Korea).
• Must show genuine comparison with similarities and differences.
• Band 3 (7-9): Some comparison but may be two separate narratives.
• Band 1 (1-3): Vague; no specific causes identified.', 101);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-101', '1. Causes of War: Long-term, Short-term, and Immediate', 'SL/HL', 'short_answer', 'P2-WAR', 15, 'To what extent was the failure of appeasement responsible for the outbreak of WWII?', '• Band 5 (13-15): Balanced evaluation of appeasement against other causes (Versailles, Hitler''s ideology, economic factors, collective security failure, Nazi-Soviet Pact).
• Appeasement: Munich Agreement (1938), failure to confront Rhineland remilitarisation (1936), emboldened Hitler, bought time but at the cost of credibility.
• Other factors: Hitler''s long-standing aims (Lebensraum, Mein Kampf), Treaty of Versailles creating grievances, Great Depression, League of Nations weakness, Soviet calculation.
• Must reach a clear, substantiated judgement.
• Band 3 (7-9): Some analysis but may overstate appeasement''s role.
• Band 1 (1-3): Minimal knowledge of pre-war diplomacy.', 102);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-102', '2. Practices and Nature of 20th-Century Wars', 'SL/HL', 'short_answer', 'P2-WAR', 15, 'Examine the impact of technology on the practices of one 20th-century war.', '• Band 5 (13-15): Detailed analysis of specific technologies and their impact on tactics, strategy, and outcomes with evaluation of significance.
• For WWI: machine guns (stalemate), gas, tanks (break stalemate), aircraft (reconnaissance then bombing), submarines (U-boat campaign).
• For WWII: blitzkrieg, strategic bombing, radar, aircraft carriers, code-breaking (Enigma/Ultra), atomic weapons.
• Must evaluate: Did technology determine outcomes? How did it change the nature of the war?
• Band 3 (7-9): Some relevant examples but limited evaluation of impact.
• Band 1 (1-3): Vague listing of technologies without analysis.', 103);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-103', '3. WWI: The Great War (1914-1918)', 'SL/HL', 'short_answer', 'P2-WAR', 15, 'To what extent was the Treaty of Versailles responsible for future conflict?', '• Band 5 (13-15): Evaluative argument linking Versailles terms to subsequent instability while considering alternative explanations.
• Versailles impact: German resentment (''diktat''), economic burden (reparations), territorial grievances, ''stab in the back'' myth, undermined Weimar legitimacy, provided ammunition for Nazi propaganda.
• Alternative factors: Great Depression, rise of fascism/communism, failure of collective security, appeasement, individual leaders'' decisions.
• Strong answers note that Versailles was harsh enough to create resentment but not harsh enough to prevent German recovery.
• Band 3 (7-9): Some relevant analysis but may be one-sided.
• Band 1 (1-3): Vague with no specific treaty terms cited.', 104);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-104', '4. WWII in Europe (1939-1945)', 'SL/HL', 'short_answer', 'P2-WAR', 15, 'Evaluate the reasons for the Allied victory in WWII in Europe.', '• Band 5 (13-15): Multi-factor analysis evaluating relative importance of different factors with specific evidence. Factors: Soviet manpower and sacrifice (80% of German casualties on Eastern Front), US industrial capacity and resources, Allied strategic bombing, D-Day and Western Front, Hitler''s strategic mistakes (Barbarossa, Stalingrad, two-front war), Allied intelligence (Enigma).
• Must evaluate which factors were most important rather than just listing them.
• Band 3 (7-9): Some relevant analysis but may not evaluate relative importance.
• Band 1 (1-3): Vague with no specific military or strategic evidence.', 105);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-105', '5. WWII in the Pacific (1941-1945)', 'SL/HL', 'short_answer', 'P2-WAR', 15, 'Evaluate the decision to use atomic weapons against Japan in 1945.', '• Band 5 (13-15): Multi-perspective evaluation with specific evidence, reaching a clear judgement. Arguments for: prevent costly invasion, end war quickly, save Allied/Japanese lives (vs. invasion), demonstrate resolve to USSR. Arguments against: Japan was already near defeat, could have demonstrated the bomb, racial motivations (would it have been used against Europeans?), civilian targeting, long-term nuclear proliferation consequences.
• Must consider different historiographical perspectives (orthodox, revisionist).
• Band 3 (7-9): Some relevant arguments but limited evaluation or balance.
• Band 1 (1-3): One-sided or factually inaccurate.', 106);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-106', '6. Effects of Wars: Political, Economic, Social', 'SL/HL', 'short_answer', 'P2-WAR', 15, 'Compare and contrast the political and economic effects of two 20th-century wars.', '• Band 5 (13-15): Systematic comparison of effects (political AND economic) with specific evidence from two wars. WWI effects: empire collapse, new states, Versailles system, economic disruption, reparations, US emergence as creditor. WWII effects: UN system, Cold War, decolonisation, Marshall Plan, economic devastation then boom, welfare states.
• Must show genuine comparison of similarities and differences.
• Band 3 (7-9): Some comparison but may focus on one war or one type of effect.
• Band 1 (1-3): Vague with no specific evidence of effects.', 107);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-107', '7. The Spanish Civil War (1936-1939)', 'SL/HL', 'short_answer', 'P2-WAR', 15, 'To what extent was foreign intervention decisive in the outcome of the Spanish Civil War?', '• Band 5 (13-15): Balanced evaluation of foreign intervention vs. domestic factors with specific evidence. Foreign intervention: German/Italian military aid to Franco (Condor Legion, troops), Soviet aid to Republic (limited and conditional), International Brigades, non-intervention by democracies (benefiting Franco). Domestic factors: Republican divisions (communists vs. anarchists vs. moderates), Nationalist unity under Franco, military advantage, Church and elite support for Franco.
• Must reach clear judgement on ''to what extent''.
• Band 3 (7-9): Some relevant analysis but may overstate one factor.
• Band 1 (1-3): Minimal knowledge of the conflict.', 108);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-108', '8. The Chinese Civil War (1927-1949)', 'SL/HL', 'short_answer', 'P2-WAR', 15, 'Evaluate the reasons for the Communist victory in the Chinese Civil War.', '• Band 5 (13-15): Multi-factor evaluation weighing CCP strengths against KMT weaknesses with specific evidence. CCP strengths: peasant mobilisation, land reform, guerrilla warfare, Mao''s leadership, party discipline, military strategy. KMT weaknesses: corruption, inflation, loss of popular support, over-reliance on cities, poor military strategy, factionalism. External factors: Japanese invasion''s differential impact, Soviet aid, limited effectiveness of US support.
• Must evaluate relative importance of factors.
• Band 3 (7-9): Some relevant factors identified but limited evaluation.
• Band 1 (1-3): Vague; no specific evidence.', 109);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-109', '9. The Korean War (1950-1953) and Vietnam War (1955-1975)', 'SL/HL', 'short_answer', 'P2-WAR', 15, 'Compare and contrast the Korean and Vietnam Wars as Cold War conflicts.', '• Band 5 (13-15): Systematic comparison across causes, nature, international involvement, and outcomes. Similarities: Cold War proxy wars, US containment policy, Chinese/Soviet involvement, ideological dimensions, Korean/Vietnamese division. Differences: Conventional vs. guerrilla warfare, UN involvement (Korea) vs. unilateral US (Vietnam), outcomes (stalemate vs. US defeat), scale and duration, domestic opposition.
• Must provide specific evidence from both conflicts.
• Band 3 (7-9): Some comparison but may be superficial.
• Band 1 (1-3): Vague; no specific evidence from either war.', 110);

