-- Flashcard topics & cards
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-auth-fc-1', '1. Origins and Rise of Authoritarian States: Conditions', '#A36B6B', 'P2-AUTH', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-1', 'What conditions favour the emergence of authoritarian states?', 'Economic crises (depression, hyperinflation), political instability (weak democratic institutions, coalition failures), social divisions (class, ethnic, religious), national humiliation (war defeat, treaty resentment), and fear of revolution (communist/capitalist threat).', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-1', 'How do economic crises lead to authoritarianism?', 'Mass unemployment and poverty create desperation, discredit existing governments, radicalise populations, and make people susceptible to promises of strong leadership and simple solutions. Examples: Great Depression enabling Hitler, Mussolini, and various military regimes.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-1', 'What is the role of political instability?', 'Weak or fragmented democratic systems (e.g., Weimar coalition instability, Chinese warlordism) create power vacuums. Citizens lose faith in democratic processes and become receptive to authoritarian alternatives promising order and stability.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-1', 'How do ideological movements contribute?', 'Fascism, communism, and various forms of nationalism provide ideological frameworks that justify authoritarian rule: the need for a strong leader, the supremacy of the state/party/race, and the rejection of liberal democracy.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-1', 'What role does fear play?', 'Fear of communism drove support for fascist/right-wing authoritarians (Italy, Germany, Spain). Fear of capitalism/imperialism drove support for communist regimes (Russia, China, Cuba). Fear of instability made populations accept authoritarian solutions.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-1', 'How does national humiliation contribute?', 'Resentment over perceived national disgrace (Treaty of Versailles for Germany, ''Century of Humiliation'' for China, Italian ''mutilated victory'') can be exploited by authoritarian leaders promising national restoration and revenge.', 6);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-auth-fc-2', '2. Methods of Establishing Authoritarian States', '#A36B6B', 'P2-AUTH', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-2', 'How did Hitler come to power?', 'Through legal-constitutional means: electoral gains, appointment as Chancellor by Hindenburg (Jan 1933), Reichstag Fire Decree (Feb 1933), Enabling Act (Mar 1933), then Gleichschaltung (coordination/consolidation) and the Night of Long Knives (1934).', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-2', 'How did Mao Zedong come to power?', 'Through prolonged revolution and civil war: building a peasant-based communist movement, the Long March (1934-35), alliance against Japan in WWII, then defeating the Nationalists (KMT) in the Chinese Civil War (1946-49), proclaiming the PRC on 1 Oct 1949.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-2', 'How did Castro come to power?', 'Through guerrilla revolution: the 26th of July Movement''s failed Moncada attack (1953), exile and return from Mexico, guerrilla campaign from the Sierra Maestra (1956-59), exploiting Batista''s corruption and US opposition, entering Havana in January 1959.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-2', 'How did Mussolini come to power?', 'Through a combination of paramilitary violence (Blackshirts/squadrismo intimidating opponents), political manoeuvring, the March on Rome (October 1922, largely a bluff), King Victor Emmanuel III''s invitation to form a government, and the Acerbo Law and Matteotti Crisis consolidating power.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-2', 'How did Stalin come to power?', 'Through political manoeuvring within the Communist Party after Lenin''s death (1924): using his position as General Secretary to build a support base, playing factions against each other (Trotsky, Zinoviev, Kamenev, Bukharin), and gradually eliminating rivals.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-2', 'What is Gleichschaltung?', 'The Nazi process of ''coordination'' or ''bringing into line'' (1933-34): banning political parties, bringing institutions (trade unions, media, courts, education) under Nazi control, and establishing totalitarian uniformity.', 6);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-auth-fc-3', '3. Consolidation of Authoritarian Power', '#A36B6B', 'P2-AUTH', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-3', 'How did authoritarian leaders consolidate power?', 'Through eliminating opposition (purges, political prisoners, banning parties), controlling institutions (judiciary, legislature, military), creating a personality cult, using propaganda, establishing secret police, and constitutional/legal changes.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-3', 'What was the Night of the Long Knives (1934)?', 'Hitler''s purge of the SA leadership (including Ernst Rohm) on 30 June 1934. It eliminated potential rivals, secured army loyalty, and demonstrated Hitler''s willingness to use extreme violence. Over 85 people were killed.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-3', 'How did Stalin consolidate power through purges?', 'The Great Purge/Terror (1936-38) eliminated perceived threats: show trials of Old Bolsheviks (Zinoviev, Kamenev, Bukharin), military purges (Marshal Tukhachevsky), mass arrests by NKVD. Up to 750,000 executed; millions sent to Gulags.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-3', 'How did Mao consolidate power?', 'Land reform (killing landlords, redistributing land), ''Resist America, Aid Korea'' campaign (Korean War), Anti-Rightist Campaign (1957), Hundred Flowers then crackdown, establishing party control over all institutions, and promoting his personality cult.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-3', 'What role does the military play in consolidation?', 'Authoritarians must secure military loyalty through purges of disloyal officers, rewards (funding, prestige), integration into the power structure, or replacement with loyal forces (e.g., SS replacing SA, PLA loyalty to Mao).', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-3', 'What role do legal/constitutional changes play?', 'Authoritarians use legal mechanisms to legitimise power: Enabling Act (Germany), Acerbo Law (Italy), new constitutions (USSR 1936, China 1954), emergency decrees, and abolishing term limits.', 6);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-auth-fc-4', '4. Nazi Germany: Domestic Policies', '#A36B6B', 'P2-AUTH', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-4', 'What was Nazi economic policy?', 'Rearmament (from 1933), public works (Autobahn), job creation schemes (RAD), Schacht''s ''New Plan'' (1934), Goering''s Four-Year Plan (1936) for autarky, ''Strength Through Joy'' (KdF) programs, suppression of trade unions, and deficit spending.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-4', 'How did the Nazis reduce unemployment?', 'From 6 million (1933) to near-zero by 1939 through: rearmament, conscription, public works, removing women/Jews from workforce, RAD (compulsory labour service), and statistical manipulation (not counting certain groups).', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-4', 'What was Nazi racial policy?', 'Based on racial hierarchy with ''Aryans'' supreme: Nuremberg Laws (1935) stripped Jews of citizenship; Kristallnacht (1938) organised violence; escalating persecution through forced emigration, ghettoisation, and ultimately the Holocaust (systematic murder of 6 million Jews).', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-4', 'How did the Nazis control society?', 'Through Gleichschaltung (coordination), Gestapo (secret police), SS, propaganda (Goebbels), education reform (Hitler Youth, curriculum changes), control of churches, censorship, book burning, and denunciation networks.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-4', 'What was the role of women in Nazi Germany?', 'The Nazis promoted ''Kinder, Kuche, Kirche'' (children, kitchen, church): women were discouraged from working, incentivised to have children (Mother''s Cross), excluded from higher education/professions, and subjected to racial breeding programs (Lebensborn).', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-4', 'What was the Hitler Youth?', 'Compulsory from 1936, it indoctrinated children aged 10-18 with Nazi ideology, physical fitness, military training (boys) and domestic skills (girls/BDM). By 1939 it had 8 million members.', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-4', 'How effective was Nazi propaganda?', 'Goebbels controlled all media (press, radio, film, art). Leni Riefenstahl''s films, mass rallies (Nuremberg), and radio (Volksempfanger) were highly effective in building support, though private resistance existed. Propaganda was central to maintaining the regime.', 7);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-auth-fc-5', '5. Stalin''s USSR: Domestic Policies', '#A36B6B', 'P2-AUTH', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-5', 'What was collectivisation?', 'Stalin''s policy (from 1929) of merging private farms into collective farms (kolkhozes) and state farms (sovkhozes). It aimed to increase agricultural output, fund industrialisation, and destroy the kulaks as a class. It caused the devastating Ukrainian famine (Holodomor, 1932-33).', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-5', 'What were the Five-Year Plans?', 'Stalin''s economic programs for rapid industrialisation: First (1928-32, heavy industry), Second (1933-37, continued heavy industry), Third (1938-41, disrupted by war). They transformed the USSR into an industrial power but at enormous human cost.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-5', 'What was the Holodomor?', 'The man-made famine in Ukraine (1932-33) caused by forced collectivisation, grain requisitioning, and deliberate Soviet policies. An estimated 3.5-7.5 million Ukrainians died. It is recognised by many countries as genocide.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-5', 'What were the Show Trials?', 'Public trials (1936-38) of former Bolshevik leaders (Zinoviev, Kamenev, Bukharin, Radek) on fabricated charges of treason, terrorism, and conspiracy. Forced confessions were extracted through torture. They served to eliminate potential rivals and terrorise the population.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-5', 'What was the Gulag system?', 'A vast network of forced labour camps across the USSR where political prisoners, ''class enemies'', and criminals were sent. Millions passed through the Gulags; conditions were brutal with high mortality. They provided slave labour for industrialisation projects.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-5', 'What was Socialist Realism?', 'The only permitted artistic style under Stalin: art, literature, and music had to glorify the Soviet state, communist values, the working class, and Stalin himself. It served as both propaganda and cultural control, suppressing creative freedom.', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-5', 'How did Stalin use the cult of personality?', 'Stalin was portrayed as the wise, benevolent ''Father of Nations'' through propaganda, renamed cities (Stalingrad), rewritten history, mandatory portraits, and controlled media. The cult served to legitimise his absolute power and create fear.', 7);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-auth-fc-6', '6. Mao''s China: Domestic Policies', '#A36B6B', 'P2-AUTH', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'What was Chinese land reform (1950-53)?', 'Mao redistributed land from landlords to peasants, involving mass ''struggle sessions'' where landlords were publicly humiliated, beaten, and often killed. An estimated 1-2 million landlords were executed. It transformed rural China and cemented peasant support for the CCP.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'What was the Great Leap Forward (1958-62)?', 'Mao''s campaign to rapidly industrialise China through people''s communes, backyard steel furnaces, and collectivised agriculture. It was an economic catastrophe causing the Great Chinese Famine (1959-61) which killed an estimated 15-55 million people.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'What was the Cultural Revolution (1966-76)?', 'Mao''s campaign to reassert his authority and purge ''capitalist roaders'' from the CCP. Red Guards (radical youth) attacked intellectuals, destroyed cultural artifacts, persecuted ''class enemies'', and caused widespread chaos. Millions were persecuted; up to 2 million died.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'Who were the Red Guards?', 'Radical young people mobilised by Mao during the Cultural Revolution to attack the ''Four Olds'' (old customs, culture, habits, ideas) and purge perceived enemies. They were eventually disbanded when their chaos became uncontrollable.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'What was the Hundred Flowers Campaign (1956-57)?', 'Mao invited intellectuals to criticise the CCP (''Let a hundred flowers bloom''). When criticism became unexpectedly harsh, Mao launched the Anti-Rightist Campaign, persecuting 500,000+ intellectuals. Debate exists over whether it was a deliberate trap.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-6', 'How did Mao control thought?', 'Through the ''Little Red Book'' (Quotations from Chairman Mao), thought reform/re-education campaigns, criticism/self-criticism sessions, propaganda, censorship, the Yan''an Rectification Movement model, and controlling all media and education.', 6);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-auth-fc-7', '7. Mussolini''s Italy: Fascist Domestic Policies', '#A36B6B', 'P2-AUTH', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-7', 'What was the Corporate State?', 'Mussolini''s economic system (from 1926) organising the economy into corporations of employers and workers under state supervision. In theory it replaced class conflict with cooperation; in practice it benefited employers and the state at workers'' expense.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-7', 'What were the Lateran Pacts (1929)?', 'Agreements between Mussolini and Pope Pius XI: recognised Vatican City as independent, made Catholicism Italy''s state religion, and provided financial compensation. They secured Church support for the regime and boosted Mussolini''s legitimacy.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-7', 'What was the Battle for Births?', 'Mussolini''s pro-natalist campaign encouraging large families through tax incentives, medals for prolific mothers, and restrictions on contraception/abortion. The goal was to increase Italy''s population from 40 million to 60 million for imperial ambitions. It largely failed.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-7', 'How did Mussolini use propaganda?', 'Through controlled media (press, radio, cinema), the cult of Il Duce (the leader), emphasis on Roman imperial glory, Fascist architecture, youth organisations (Balilla, ONB), spectacles, and sport (1934 World Cup). The image of a virile, decisive leader was central.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-7', 'What was OVRA?', 'The Organisation for Vigilance and Repression of Anti-Fascism - Mussolini''s secret police. While less brutal than the Gestapo or NKVD, OVRA monitored dissidents, used informants, and sent political opponents to confino (internal exile).', 5);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-auth-fc-8', '8. Castro''s Cuba: Revolutionary State', '#A36B6B', 'P2-AUTH', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-8', 'How did Castro consolidate power after 1959?', 'Trials and executions of Batista supporters, nationalisation of US-owned businesses, agrarian reform, alliance with the USSR, establishing a one-party state, suppressing political opponents (imprisoning dissidents), and building a personality cult.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-8', 'What were Cuba''s social achievements?', 'Universal free healthcare (one of the best in the developing world), literacy campaign (1961 reduced illiteracy from 23% to 4%), free education, racial equality improvements, and low infant mortality rates. These are often cited as socialism''s successes.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-8', 'What were Cuba''s economic challenges?', 'US trade embargo (from 1960), dependence on Soviet subsidies, sugar monoculture, failed diversification attempts, rationing, limited consumer goods, and severe economic crisis after Soviet collapse (1991 ''Special Period'').', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-8', 'How did Castro suppress opposition?', 'Through political imprisonment, censorship of media, banning opposition parties, surveillance (CDR - Committees for the Defence of the Revolution), forcing emigration of opponents (Mariel boatlift 1980), and control of all institutions.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-8', 'What was Cuba''s international role?', 'Castro pursued revolutionary internationalism: military support for Angola, aid to liberation movements in Africa and Latin America, hosting guerrilla training, alliance with USSR, and defiance of US (Bay of Pigs, Missile Crisis).', 5);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-auth-fc-9', '9. Propaganda, Media, and Control of Information', '#A36B6B', 'P2-AUTH', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-9', 'Why is propaganda essential for authoritarian regimes?', 'It builds support and legitimacy, creates a shared narrative, demonises opponents, maintains a personality cult, controls information flow, mobilises the population, and shapes beliefs. Without propaganda, regimes rely entirely on coercion, which is more costly.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-9', 'How did Nazi propaganda work?', 'Goebbels'' Ministry of Propaganda controlled all media. Techniques included: mass rallies (Nuremberg), radio (Volksempfanger), film (Triumph of the Will), posters, book burning, censorship, antisemitic messaging, and promoting the Fuhrer myth.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-9', 'How did Soviet propaganda work?', 'State control of all media (Pravda, Izvestia), Socialist Realism in art, rewriting history (airbrushing purged leaders from photos), education/indoctrination, mass spectacles, cult of Lenin then Stalin, and controlled public celebrations.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-9', 'How did Mao use propaganda?', 'The Little Red Book (Quotations from Chairman Mao), mass campaigns, posters, controlled media (People''s Daily), loudspeakers, revolutionary operas, criticism/self-criticism sessions, and the cult of personality (badges, portraits, songs).', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-9', 'What role does education play in authoritarian control?', 'Education systems are reformed to indoctrinate youth: rewritten textbooks, loyalty oaths, mandatory participation in regime organisations (Hitler Youth, Pioneers, Red Guards), teacher monitoring, and emphasis on ideology over critical thinking.', 5);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-auth-fc-10', '10. Treatment of Opposition and Resistance', '#A36B6B', 'P2-AUTH', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-10', 'How did authoritarian states treat political opposition?', 'Through banning opposition parties, secret police surveillance, imprisonment/execution, show trials, forced exile, concentration/labour camps, denunciation systems, and making examples of prominent dissidents to terrorise others.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-10', 'What forms of resistance existed in Nazi Germany?', 'White Rose group (student pamphlets), Confessing Church (some clergy), military plots (20 July 1944 Stauffenberg plot), communist underground networks, Edelweiss Pirates (youth), and individual acts of non-compliance. All were small-scale and unsuccessful.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-10', 'What forms of resistance existed in the USSR?', 'Very limited under Stalin: some worker resistance (go-slows), intellectual dissidence (later samizdat underground publishing), national resistance in occupied territories, and defections. The NKVD''s pervasive terror made organised resistance nearly impossible.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-10', 'How did Mao deal with opposition?', 'Anti-Rightist Campaign (1957), Cultural Revolution persecution, labour camps (laogai), ''re-education through labour'', struggle sessions, forced confessions, executions, and sending urban youth to the countryside (rustication).', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-auth-fc-11', '11. Foreign Policy of Authoritarian States', '#A36B6B', 'P2-AUTH', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-11', 'What were Hitler''s foreign policy aims?', 'Overturn Versailles, unite all German speakers (Grossdeutschland), achieve Lebensraum (living space) in the East, destroy communism, and establish German racial dominance in Europe.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-11', 'What was Mussolini''s foreign policy?', 'Restore Roman imperial glory, create a Mediterranean empire (Mare Nostrum), expand in Africa (Ethiopia 1935-36, Libya), establish Italian great-power status, and use foreign adventures to build domestic support.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-11', 'What was Stalin''s foreign policy?', 'Initially ''Socialism in One Country'' (focusing on domestic industrialisation), then collective security (joining League of Nations 1934), Nazi-Soviet Pact (1939), and post-WWII expansion of Soviet influence in Eastern Europe.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-11', 'How did Mao conduct foreign policy?', 'Alliance with USSR (Sino-Soviet Treaty 1950), intervention in Korean War (1950-53), support for revolutionary movements globally, Sino-Soviet Split (from late 1950s), and eventual rapprochement with the US (Nixon visit 1972).', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-auth-fc-12', '12. Treatment of Women and Minorities in Authoritarian States', '#A36B6B', 'P2-AUTH', 12);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-12', 'How were women treated in Nazi Germany?', 'Relegated to ''Kinder, Kuche, Kirche'' (children, kitchen, church), excluded from professions, encouraged to breed through Mother''s Cross medals, subjected to Lebensborn programs, but ironically needed in workforce during war.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-12', 'How were women treated in the USSR?', 'Officially equal: women gained suffrage, access to education and professions, and abortion rights. In practice, they faced the ''double burden'' (work + domestic duties), glass ceilings, and Stalin reversed some early Bolshevik gains (restricted abortion 1936).', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-12', 'How were women treated in Mao''s China?', 'The Marriage Law (1950) abolished arranged marriages and gave women divorce rights. Women entered the workforce (''Women hold up half the sky''). However, traditional patriarchal attitudes persisted, and women rarely held top political positions.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-auth-fc-12', 'How did authoritarian states treat ethnic/religious minorities?', 'Nazi Germany: genocide of Jews (Holocaust), Roma, disabled. USSR: deportation of ethnic groups (Chechens, Crimean Tatars, Volga Germans). Italy: anti-Semitic laws (1938). China: suppression of Tibetans, Uyghurs.', 4);

-- MCQ questions
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-231', '1. Origins and Rise of Authoritarian States: Conditions', 'SL/HL', 'P2-AUTH', 'Which factor was common to the rise of both Hitler and Mussolini?', 'Colonial ambitions', 'Post-WWI national resentment and economic crisis', 'Communist revolution', 'Religious extremism', 1, 'See mark scheme for detailed explanation.', 232);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-232', '1. Origins and Rise of Authoritarian States: Conditions', 'SL/HL', 'P2-AUTH', 'Fear of communism particularly benefited:', 'Left-wing democratic parties', 'Right-wing/fascist authoritarian movements', 'Trade unions', 'Socialist parties', 1, 'See mark scheme for detailed explanation.', 233);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-233', '1. Origins and Rise of Authoritarian States: Conditions', 'SL/HL', 'P2-AUTH', 'China''s ''Century of Humiliation'' refers to:', 'Communist rule under Mao', 'The period of foreign domination from the Opium Wars to 1949', 'Japanese occupation only', 'The Cultural Revolution', 1, 'See mark scheme for detailed explanation.', 234);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-234', '1. Origins and Rise of Authoritarian States: Conditions', 'SL/HL', 'P2-AUTH', 'Which is NOT a condition favouring authoritarian emergence?', 'Strong democratic institutions and traditions', 'Economic depression', 'National humiliation', 'Weak coalition governments', 0, 'See mark scheme for detailed explanation.', 235);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-235', '2. Methods of Establishing Authoritarian States', 'SL/HL', 'P2-AUTH', 'The Enabling Act (1933) allowed Hitler to:', 'Declare war on France', 'Pass laws without the Reichstag', 'Abolish the presidency', 'Invade Poland', 1, 'See mark scheme for detailed explanation.', 236);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-236', '2. Methods of Establishing Authoritarian States', 'SL/HL', 'P2-AUTH', 'Mao''s Long March (1934-35) was significant because it:', 'Defeated the KMT immediately', 'Preserved the Communist movement and established Mao''s leadership', 'Ended the Japanese occupation', 'Established the PRC', 1, 'See mark scheme for detailed explanation.', 237);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-237', '2. Methods of Establishing Authoritarian States', 'SL/HL', 'P2-AUTH', 'Castro''s revolution succeeded in:', '1953', '1956', '1959', '1961', 2, 'See mark scheme for detailed explanation.', 238);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-238', '2. Methods of Establishing Authoritarian States', 'SL/HL', 'P2-AUTH', 'The March on Rome (1922) resulted in:', 'A violent overthrow of the Italian government', 'King Victor Emmanuel III inviting Mussolini to form a government', 'A communist revolution', 'Democratic elections', 1, 'See mark scheme for detailed explanation.', 239);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-239', '2. Methods of Establishing Authoritarian States', 'SL/HL', 'P2-AUTH', 'Stalin consolidated power primarily through:', 'Military conquest', 'Political manoeuvring within the Communist Party', 'Foreign invasion', 'Popular elections', 1, 'See mark scheme for detailed explanation.', 240);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-240', '3. Consolidation of Authoritarian Power', 'SL/HL', 'P2-AUTH', 'The Great Purge in the USSR occurred during:', '1924-26', '1929-31', '1936-38', '1941-43', 2, 'See mark scheme for detailed explanation.', 241);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-241', '3. Consolidation of Authoritarian Power', 'SL/HL', 'P2-AUTH', 'The Night of the Long Knives targeted:', 'The German military', 'SA leadership including Ernst Rohm', 'The Reichstag', 'Jewish communities', 1, 'See mark scheme for detailed explanation.', 242);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-242', '3. Consolidation of Authoritarian Power', 'SL/HL', 'P2-AUTH', 'Mao''s Anti-Rightist Campaign (1957) followed:', 'The Long March', 'The Hundred Flowers movement', 'The Cultural Revolution', 'The Great Leap Forward', 1, 'See mark scheme for detailed explanation.', 243);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-243', '3. Consolidation of Authoritarian Power', 'SL/HL', 'P2-AUTH', 'Which was a common method of consolidation across authoritarian states?', 'Holding free elections', 'Establishing secret police forces', 'Decentralising power', 'Expanding judicial independence', 1, 'See mark scheme for detailed explanation.', 244);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-244', '4. Nazi Germany: Domestic Policies', 'SL/HL', 'P2-AUTH', 'The Nuremberg Laws (1935) primarily:', 'Established rearmament', 'Stripped Jews of German citizenship', 'Created the Hitler Youth', 'Banned trade unions', 1, 'See mark scheme for detailed explanation.', 245);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-245', '4. Nazi Germany: Domestic Policies', 'SL/HL', 'P2-AUTH', 'Kristallnacht (November 1938) involved:', 'A military coup', 'Organised violence against Jews and Jewish property', 'The invasion of Austria', 'A workers'' strike', 1, 'See mark scheme for detailed explanation.', 246);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-246', '4. Nazi Germany: Domestic Policies', 'SL/HL', 'P2-AUTH', 'The Nazi slogan for women''s role was:', 'Blood and Soil', 'Strength Through Joy', 'Kinder, Kuche, Kirche', 'Ein Volk, Ein Reich, Ein Fuhrer', 2, 'See mark scheme for detailed explanation.', 247);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-247', '4. Nazi Germany: Domestic Policies', 'SL/HL', 'P2-AUTH', 'Goering''s Four-Year Plan (1936) aimed at:', 'Full employment', 'Economic autarky (self-sufficiency)', 'Free trade', 'Agricultural reform only', 1, 'See mark scheme for detailed explanation.', 248);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-248', '4. Nazi Germany: Domestic Policies', 'SL/HL', 'P2-AUTH', 'Nazi propaganda was overseen by:', 'Himmler', 'Goering', 'Goebbels', 'Speer', 2, 'See mark scheme for detailed explanation.', 249);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-249', '5. Stalin''s USSR: Domestic Policies', 'SL/HL', 'P2-AUTH', 'The Holodomor (1932-33) was:', 'A military defeat', 'A man-made famine in Ukraine caused by collectivisation', 'An industrial accident', 'A natural disaster', 1, 'See mark scheme for detailed explanation.', 250);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-250', '5. Stalin''s USSR: Domestic Policies', 'SL/HL', 'P2-AUTH', 'The First Five-Year Plan (1928-32) focused on:', 'Agriculture', 'Consumer goods', 'Heavy industry', 'Military expansion', 2, 'See mark scheme for detailed explanation.', 251);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-251', '5. Stalin''s USSR: Domestic Policies', 'SL/HL', 'P2-AUTH', 'Which Old Bolshevik was NOT a victim of the Show Trials?', 'Zinoviev', 'Kamenev', 'Bukharin', 'Molotov', 3, 'See mark scheme for detailed explanation.', 252);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-252', '5. Stalin''s USSR: Domestic Policies', 'SL/HL', 'P2-AUTH', 'Socialist Realism required art to:', 'Express individual creativity', 'Glorify the Soviet state and communist values', 'Critique government policies', 'Follow Western artistic trends', 1, 'See mark scheme for detailed explanation.', 253);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-253', '5. Stalin''s USSR: Domestic Policies', 'SL/HL', 'P2-AUTH', 'The Gulag system primarily served to:', 'Rehabilitate criminals', 'Provide slave labour and terrorise the population', 'Educate political dissidents', 'House war refugees', 1, 'See mark scheme for detailed explanation.', 254);
