-- Written questions (15 marks)
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-110', '1. Origins and Rise of Authoritarian States: Conditions', 'SL/HL', 'short_answer', 'P2-AUTH', 15, 'Compare the conditions that led to the emergence of two authoritarian states, each from a different region.', '• Band 5 (13-15): Detailed comparative analysis of conditions (economic, political, social, ideological) in two states from different regions with specific evidence.
• Examples: Nazi Germany (Weimar weakness, Great Depression, Versailles resentment, fear of communism) vs. Mao''s China (warlordism, Japanese invasion, peasant poverty, nationalist failure).
• Or: Mussolini''s Italy (mutilated victory, biennio rosso, liberal state weakness) vs. Castro''s Cuba (Batista''s corruption, US domination, rural poverty).
• Must show genuine comparison with similarities and differences.
• Band 3 (7-9): Some comparison but may be implicit; two separate narratives.
• Band 1 (1-3): Vague generalisations without specific evidence.', 111);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-111', '1. Origins and Rise of Authoritarian States: Conditions', 'SL/HL', 'short_answer', 'P2-AUTH', 15, 'To what extent were economic factors the most important condition for the emergence of authoritarian states?', '• Band 5 (13-15): Balanced evaluation weighing economic factors against political, social, ideological, and external factors. Multiple case studies with specific evidence.
• Economic: Great Depression, hyperinflation, poverty, inequality, trade disruption.
• Non-economic: political instability, national humiliation, ideological appeal, charismatic leadership, fear of communism/capitalism, weak institutions.
• Must reach clear, substantiated judgement on ''to what extent''.
• Band 3 (7-9): Some relevant analysis but may lack balance or specific evidence.
• Band 1 (1-3): Generalised claims without supporting evidence.', 112);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-112', '2. Methods of Establishing Authoritarian States', 'SL/HL', 'short_answer', 'P2-AUTH', 15, 'Compare and contrast the methods used to establish two authoritarian states.', '• Band 5 (13-15): Systematic comparison of methods (legal, revolutionary, military) with detailed evidence from two states.
• Examples: Hitler (legal/constitutional route, Enabling Act, Gleichschaltung) vs. Mao (revolutionary guerrilla warfare, civil war, peasant mobilisation).
• Or: Mussolini (paramilitary violence + political manoeuvre) vs. Castro (guerrilla revolution from Sierra Maestra).
• Must compare the methods used, explain why different methods were chosen (context), and evaluate relative effectiveness.
• Band 3 (7-9): Some comparison but may be two separate narratives.
• Band 1 (1-3): Vague; no specific evidence or genuine comparison.', 113);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-113', '3. Consolidation of Authoritarian Power', 'SL/HL', 'short_answer', 'P2-AUTH', 15, 'Evaluate the methods used by one authoritarian leader to consolidate power.', '• Band 5 (13-15): Detailed evaluation of multiple methods (terror, propaganda, legal changes, institutional control, cult of personality) with specific evidence and assessment of effectiveness.
• For Hitler: Enabling Act, Night of Long Knives, Gleichschaltung, banning parties/unions, SS/Gestapo, 1934 combining President/Chancellor roles.
• For Stalin: Political manoeuvring, show trials, Great Purge, NKVD, Gulags, 1936 Constitution, personality cult.
• For Mao: Land reform, Korean War mobilisation, Anti-Rightist Campaign, military loyalty (PLA), party control.
• Must evaluate: How effective? How interconnected? Which were most important?
• Band 3 (7-9): Descriptive account of methods without full evaluation.
• Band 1 (1-3): Vague; minimal specific evidence.', 114);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-114', '4. Nazi Germany: Domestic Policies', 'SL/HL', 'short_answer', 'P2-AUTH', 15, 'To what extent did the Nazi regime maintain power through consent rather than coercion?', '• Band 5 (13-15): Balanced evaluation of consent (propaganda, economic recovery, national pride, KdF) vs. coercion (Gestapo, SS, concentration camps, terror) with specific evidence. Consent factors: economic recovery (unemployment down), Volksgemeinschaft appeal, propaganda effectiveness, foreign policy successes (Rhineland, Anschluss), KdF leisure programs. Coercion factors: Gestapo, SS, concentration camps, denunciation networks, legal persecution, Night of Long Knives, book burning, censorship.
• Strong answers recognise the interplay: consent was partly manufactured through coercion, and the two cannot be fully separated.
• Band 3 (7-9): Some analysis but may overemphasise one factor.
• Band 1 (1-3): Generalised; no specific evidence.', 115);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-115', '4. Nazi Germany: Domestic Policies', 'SL/HL', 'short_answer', 'P2-AUTH', 15, 'Evaluate the impact of Nazi policies on one social group (e.g., women, youth, Jews, workers).', '• Band 5 (13-15): Detailed analysis of policies and their impact on the chosen group, with evaluation of extent of change and success.
• For women: KKK ideology, Mother''s Cross, exclusion from professions, Lebensborn, but wartime reversal (needed in workforce).
• For Jews: progressive persecution (boycotts, Nuremberg Laws, Kristallnacht, ghettoisation, Holocaust).
• For youth: Hitler Youth, BDM, education reform, indoctrination, military training, but evidence of resistance (Edelweiss Pirates, White Rose).
• Must evaluate: How successful were the policies? What resistance existed?
• Band 3 (7-9): Descriptive with some analysis.
• Band 1 (1-3): Minimal knowledge of policies or impact.', 116);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-116', '5. Stalin''s USSR: Domestic Policies', 'SL/HL', 'short_answer', 'P2-AUTH', 15, 'Evaluate the economic policies of Stalin''s USSR.', '• Band 5 (13-15): Balanced evaluation of successes (industrialisation, military-industrial growth, urbanisation) and failures (agricultural devastation, famine, human cost, inefficiency) with specific evidence. Successes: USSR became world''s second industrial power; steel, coal, electricity output massively increased; military preparation for WWII. Failures: Holodomor (millions dead), collectivisation disrupted agriculture, consumer goods neglected, Gulag slave labour, statistics unreliable, environmental damage.
• Must weigh whether the economic transformation justified the human cost.
• Band 3 (7-9): Some relevant analysis but may be one-sided.
• Band 1 (1-3): Minimal specific evidence.', 117);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-117', '5. Stalin''s USSR: Domestic Policies', 'SL/HL', 'short_answer', 'P2-AUTH', 15, 'To what extent was fear the main tool used by Stalin to maintain control?', '• Band 5 (13-15): Evaluative argument weighing fear/terror against other control mechanisms with detailed evidence. Fear: Great Purge, Show Trials, NKVD/secret police, Gulag, denunciations, arbitrary arrests, torture, executions.
• Other tools: propaganda, cult of personality, Socialist Realism, education/indoctrination, economic improvements for some, party loyalty, censorship, rewriting history.
• Strong answers recognise that fear and other methods were interconnected.
• Band 3 (7-9): Narrative with some analysis; may overemphasise fear or neglect other factors.
• Band 1 (1-3): Generalised with no specific evidence.', 118);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-118', '6. Mao''s China: Domestic Policies', 'SL/HL', 'short_answer', 'P2-AUTH', 15, 'To what extent was the Cultural Revolution a failure?', '• Band 5 (13-15): Balanced evaluation considering Mao''s goals vs. outcomes with detailed evidence. Mao''s goals: reassert authority, purge rivals (Liu Shaoqi, Deng Xiaoping), prevent ''revisionism'', maintain revolutionary spirit. Successes (from Mao''s perspective): removed rivals, reasserted dominance, reinvigorated revolutionary ideology temporarily. Failures: economic devastation, cultural destruction, millions persecuted/killed, educational system collapsed, chaos required military intervention, ultimately discredited radical Maoism.
• Must define ''failure'' and evaluate from multiple perspectives.
• Band 3 (7-9): Some analysis but may be one-sided.
• Band 1 (1-3): Vague with no specific evidence.', 119);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-119', '6. Mao''s China: Domestic Policies', 'SL/HL', 'short_answer', 'P2-AUTH', 15, 'Compare and contrast the domestic policies of Mao Zedong and Joseph Stalin.', '• Band 5 (13-15): Systematic comparison across multiple policy areas (economic, social, political, cultural) with specific evidence from both states.
• Economic: Both pursued rapid industrialisation and collectivisation; both caused massive famines (Holodomor vs. Great Famine); Five-Year Plans vs. Great Leap Forward. Political: Both used purges (Great Purge vs. Anti-Rightist/Cultural Revolution); personality cults; show trials vs. struggle sessions. Social: Both controlled education, art, culture; both targeted intellectuals. Differences: Mao mobilised youth (Red Guards); Stalin relied more on secret police; different ideological emphases (peasant vs. proletarian revolution).
• Band 3 (7-9): Some comparison but may focus on one leader.
• Band 1 (1-3): Vague generalisations without specific evidence.', 120);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-120', '7. Mussolini''s Italy: Fascist Domestic Policies', 'SL/HL', 'short_answer', 'P2-AUTH', 15, 'To what extent was Mussolini''s Italy a totalitarian state?', '• Band 5 (13-15): Evaluative argument defining totalitarianism and assessing Italy against the criteria, with specific evidence for and against. Totalitarian features: one-party state, cult of personality, propaganda, OVRA, youth indoctrination, Corporate State, suppression of opposition. Limitations: King retained position, Church maintained independence (Lateran Pacts compromise), OVRA less brutal than Gestapo, southern Italy barely penetrated by Fascism, traditional elites retained influence.
• Must compare with ''fully'' totalitarian states (Nazi Germany, Stalinist USSR) to calibrate assessment.
• Band 3 (7-9): Some analysis but may not fully define or evaluate totalitarianism.
• Band 1 (1-3): Vague; no clear argument or specific evidence.', 121);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-121', '8. Castro''s Cuba: Revolutionary State', 'SL/HL', 'short_answer', 'P2-AUTH', 15, 'Evaluate the domestic policies of Castro''s Cuba, considering both achievements and limitations.', '• Band 5 (13-15): Balanced evaluation weighing social achievements against political repression and economic problems with specific evidence. Achievements: healthcare, literacy, education, racial equality, infant mortality reduction. Limitations: political repression (no free elections, censorship, political prisoners), economic failure (dependence on USSR, rationing, emigration), limited personal freedoms.
• Must weigh whether social gains justify political repression, offering a clear judgement.
• Band 3 (7-9): Some analysis but may be one-sided or lack specific evidence.
• Band 1 (1-3): Vague generalisations.', 122);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-122', '9. Propaganda, Media, and Control of Information', 'SL/HL', 'short_answer', 'P2-AUTH', 15, 'Compare the use of propaganda by two authoritarian leaders.', '• Band 5 (13-15): Systematic comparison of propaganda methods, content, and effectiveness across two leaders with specific evidence. Methods: media control, personality cult, film/art, rallies, education, censorship. Content: ideology promoted, enemies demonised, leader glorified, achievements exaggerated. Effectiveness: how successfully did propaganda build support? What were its limits?
• Must show genuine comparison with both similarities and differences.
• Band 3 (7-9): Some comparison but may be two separate descriptions.
• Band 1 (1-3): Vague; no specific examples of propaganda.', 123);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-123', '10. Treatment of Opposition and Resistance', 'SL/HL', 'short_answer', 'P2-AUTH', 15, 'Evaluate the extent and effectiveness of resistance to one authoritarian regime.', '• Band 5 (13-15): Detailed evaluation of different forms of resistance (political, military, intellectual, passive) with assessment of their impact and limitations.
• For Nazi Germany: White Rose, Confessing Church, Stauffenberg plot, Edelweiss Pirates, communist cells - all limited and ultimately unsuccessful due to Gestapo effectiveness.
• For USSR: minimal under Stalin; later dissident movement (Solzhenitsyn, Sakharov); samizdat; national resistance.
• Must evaluate WHY resistance was limited and whether it had any impact (even symbolic).
• Band 3 (7-9): Some knowledge of resistance but limited evaluation.
• Band 1 (1-3): Vague; cannot name specific resistance movements.', 124);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-124', '11. Foreign Policy of Authoritarian States', 'SL/HL', 'short_answer', 'P2-AUTH', 15, 'Compare and contrast the foreign policies of two authoritarian rulers.', '• Band 5 (13-15): Systematic comparison of aims, methods, and outcomes with specific evidence from two rulers. May compare: Hitler and Mussolini (both expansionist, alliance/rivalry, different scale); or Stalin and Mao (communist states, alliance then split, different strategic contexts).
• Must analyse similarities and differences in aims, methods, and success.
• Strong answers connect foreign policy to domestic needs and ideology.
• Band 3 (7-9): Some comparison but may be two separate narratives.
• Band 1 (1-3): Vague with no specific foreign policy evidence.', 125);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-125', '12. Treatment of Women and Minorities in Authoritarian States', 'SL/HL', 'short_answer', 'P2-AUTH', 15, 'Compare the status of women under two authoritarian regimes.', '• Band 5 (13-15): Systematic comparison of policies toward women (legal rights, economic role, social expectations, propaganda) with specific evidence and evaluation.
• Examples: Nazi Germany (domestic role, KKK) vs. USSR (official equality, double burden) or China (Marriage Law, workforce participation).
• Must compare both official policy AND actual reality.
• Strong answers evaluate the extent of genuine change vs. propaganda.
• Band 3 (7-9): Some comparison but may lack specific evidence or focus on one state.
• Band 1 (1-3): Vague generalisations.', 126);

