-- Flashcard topics & cards
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-cold-fc-1', '1. Origins of the Cold War (1945-1947)', '#6B8BA3', 'P2-COLD', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-1', 'What were the ideological origins of the Cold War?', 'Fundamental incompatibility between US capitalism/liberal democracy and Soviet communism/one-party state. Mutual suspicion dating from the 1917 Russian Revolution, US intervention in the Russian Civil War, and the Nazi-Soviet Pact (1939).', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-1', 'What happened at the Yalta Conference (February 1945)?', 'FDR, Churchill, and Stalin agreed on: Germany''s division into occupation zones, free elections in liberated Eastern Europe (vaguely defined), Soviet entry into the Pacific War, and the creation of the United Nations. Disagreements were papered over.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-1', 'What happened at the Potsdam Conference (July-Aug 1945)?', 'Truman (replacing FDR), Attlee (replacing Churchill), and Stalin revealed growing tensions: disagreements over German reparations, Polish borders, and Eastern European elections. Truman informed Stalin of the atomic bomb, increasing Soviet suspicion.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-1', 'What was the Iron Curtain?', 'Churchill''s famous phrase (Fulton, Missouri speech, March 1946) describing the Soviet-imposed division of Europe: communist states under Soviet control in the East vs. democratic states in the West. It became the defining metaphor of Cold War division.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-1', 'What was the Truman Doctrine (1947)?', 'Truman declared the US would support ''free peoples'' resisting subjugation by armed minorities or outside pressure. Initially applied to Greece and Turkey ($400 million in aid), it established the containment policy that guided US foreign policy throughout the Cold War.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-1', 'What was the Marshall Plan (1947)?', 'US program providing $13 billion in economic aid to rebuild Western Europe. Its aims were economic recovery, preventing communist appeal in impoverished countries, creating markets for US exports, and strengthening the Western bloc. The USSR rejected participation and pressured Eastern Europe to do the same.', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-1', 'What was Soviet ''satellisation'' of Eastern Europe?', 'Between 1945-48, the USSR established communist governments throughout Eastern Europe through rigged elections, intimidation, and coups: Poland, Romania, Bulgaria, Hungary, Czechoslovakia (1948 Prague coup), and East Germany. These became Soviet satellite states.', 7);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-cold-fc-2', '2. Berlin and the German Question (1948-1961)', '#6B8BA3', 'P2-COLD', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-2', 'What caused the Berlin Blockade (1948-49)?', 'Western Allies introduced a new currency (Deutschmark) in their zones without Soviet agreement. Stalin blockaded all road and rail access to West Berlin to force the Allies out and prevent a divided Germany. The Allies responded with the Berlin Airlift.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-2', 'What was the Berlin Airlift?', 'For 11 months (June 1948 - May 1949), Western Allies flew supplies into West Berlin: over 2 million tons of food, fuel, and supplies in 278,000 flights. It demonstrated Western resolve and was a major Cold War propaganda victory.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-2', 'What was the significance of the Berlin Blockade?', 'It solidified the division of Germany (FRG created May 1949, GDR created October 1949), led to the creation of NATO (April 1949), demonstrated the Cold War''s potential for confrontation, and made Berlin a symbol of Cold War tension.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-2', 'Why was the Berlin Wall built (August 1961)?', 'To stop the mass exodus of East Germans to the West through Berlin (3.5 million had left since 1945, draining skilled workers). Khrushchev approved the wall after failed ultimatums demanding Western withdrawal from Berlin.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-2', 'What was the impact of the Berlin Wall?', 'It physically divided families and a city, became the most powerful symbol of the Cold War, ended the Berlin crisis, stabilised the GDR (by stopping emigration), but was a propaganda disaster for communism worldwide.', 5);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-cold-fc-3', '3. The Nuclear Arms Race and Deterrence', '#6B8BA3', 'P2-COLD', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-3', 'How did the nuclear arms race develop?', 'US atomic bomb (1945), Soviet atomic bomb (1949), US hydrogen bomb (1952), Soviet H-bomb (1953), ICBMs (late 1950s), MIRVs (1970s). By the 1980s, both sides had enough weapons to destroy the world many times over (overkill).', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-3', 'What is MAD (Mutually Assured Destruction)?', 'The Cold War doctrine that both superpowers possessed enough nuclear weapons to destroy each other completely, making nuclear war irrational for either side. MAD created a paradoxical stability: weapons too destructive to use.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-3', 'What was the significance of Sputnik (1957)?', 'The Soviet launch of the first satellite demonstrated ICBM capability and shocked the US (''Sputnik crisis''). It triggered the Space Race, increased US defence spending, created NASA, and intensified fears of a ''missile gap''.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-3', 'What arms control agreements were reached?', 'Limited Test Ban Treaty (1963, banned atmospheric testing), Non-Proliferation Treaty (NPT, 1968), SALT I (1972, limited ABM systems and froze ICBMs), SALT II (1979, limited warheads but never ratified), INF Treaty (1987, eliminated intermediate-range missiles).', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-cold-fc-4', '4. The Cuban Missile Crisis (1962)', '#6B8BA3', 'P2-COLD', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-4', 'What caused the Cuban Missile Crisis?', 'Soviet decision to place nuclear missiles in Cuba (90 miles from US), motivated by: defending Cuba from US invasion (Bay of Pigs 1961), redressing nuclear imbalance (US had more ICBMs + Jupiter missiles in Turkey), and Khrushchev''s desire to score a Cold War victory.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-4', 'What was the Bay of Pigs (April 1961)?', 'A failed CIA-backed invasion of Cuba by Cuban exiles. Its failure embarrassed the US, strengthened Castro, pushed Cuba closer to the USSR, and convinced Khrushchev that Kennedy was weak - contributing to the missile crisis.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-4', 'How was the crisis resolved?', 'After 13 days of intense confrontation (16-28 October 1962): Kennedy imposed a naval ''quarantine'' (blockade), exchanged letters with Khrushchev, and agreed a deal: USSR removed missiles from Cuba; US pledged not to invade Cuba and secretly removed Jupiter missiles from Turkey.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-4', 'What were the consequences of the crisis?', 'Moscow-Washington hotline established (1963), Limited Test Ban Treaty (1963), beginning of detente, both sides recognised the danger of nuclear brinkmanship, Khrushchev weakened (contributed to his 1964 removal), and Cuba''s security was guaranteed.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-4', 'How close did the world come to nuclear war?', 'Extremely close: Soviet submarine captain Vasili Arkhipov refused to authorise a nuclear torpedo; US reconnaissance aircraft were shot at; communication delays risked miscalculation. It was likely the closest the Cold War came to nuclear war.', 5);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-cold-fc-5', '5. Detente (1969-1979)', '#6B8BA3', 'P2-COLD', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-5', 'What was detente?', 'A period of reduced Cold War tensions characterised by increased diplomacy, arms control, and trade between the superpowers (roughly 1969-1979). It was driven by mutual exhaustion, nuclear danger awareness, economic pressures, and Sino-Soviet split opportunities.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-5', 'What were the key events of detente?', 'Nixon''s visit to China (1972), SALT I (1972), Helsinki Accords (1975), Apollo-Soyuz mission (1975), increased US-Soviet trade, and various diplomatic summits. It represented a pragmatic approach to managing superpower competition.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-5', 'What was Nixon''s ''triangular diplomacy''?', 'Nixon and Kissinger exploited the Sino-Soviet Split by opening relations with China (1972), creating a strategic triangle. This gave the US leverage: both communist powers competed for better relations with Washington.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-5', 'What were the Helsinki Accords (1975)?', 'Agreements signed by 35 states at the CSCE: recognised post-WWII European borders (Soviet aim), committed to human rights and freedoms (Western aim, later used by dissidents in Eastern Europe), and promoted economic cooperation.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-5', 'Why did detente collapse?', 'Soviet invasion of Afghanistan (1979), continued Soviet military build-up, human rights concerns (Jackson-Vanik Amendment), Soviet support for Third World movements, US domestic opposition (neoconservatives), and Reagan''s election (1980) ending detente.', 5);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-cold-fc-6', '6. Cold War in Asia, Latin America, and Africa (Proxy Conflicts)', '#6B8BA3', 'P2-COLD', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-6', 'What were Cold War proxy wars?', 'Conflicts in the Third World where superpowers supported opposing sides without directly fighting each other: Korea (1950-53), Vietnam (1955-75), Angola (1975-2002), Afghanistan (1979-89), and various others in Latin America, Africa, and the Middle East.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-6', 'How did the Cold War affect Latin America?', 'US intervention to prevent communist influence: CIA-backed coups (Guatemala 1954, Chile 1973), support for anti-communist dictators, Alliance for Progress aid, Cuban Missile Crisis, support for Contras in Nicaragua, and invasion of Grenada (1983).', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-6', 'What was the Soviet-Afghan War (1979-1989)?', 'Soviet invasion to support a communist government facing Islamist insurgency. The US armed the Mujahideen (including Stinger missiles). It became the USSR''s ''Vietnam'': costly, unwinnable, and contributing to Soviet collapse. ~1 million Afghans died.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-6', 'How did the Cold War affect Africa?', 'Both superpowers competed for influence: supported opposing factions in Angola, Mozambique, Ethiopia, Somalia; backed friendly regimes regardless of human rights; and complicated decolonisation by importing ideological rivalries.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-6', 'What was the Non-Aligned Movement?', 'Founded in 1961 by Nehru, Nasser, Tito, Sukarno, and Nkrumah. NAM states refused to align with either superpower bloc, seeking independent foreign policies. In practice, alignment often shifted, and both superpowers courted NAM members.', 5);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-cold-fc-7', '7. The Second Cold War and Reagan (1979-1985)', '#6B8BA3', 'P2-COLD', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-7', 'What was the ''Second Cold War''?', 'The period of renewed US-Soviet tension (roughly 1979-85) characterised by: Soviet invasion of Afghanistan, Reagan''s aggressive anti-communist rhetoric (''Evil Empire''), military build-up, SDI, NATO Euromissile deployments, and collapse of arms control dialogue.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-7', 'What was Reagan''s approach to the Cold War?', 'Reagan pursued ''peace through strength'': massive military spending increase, SDI (''Star Wars''), support for anti-communist insurgencies worldwide (Reagan Doctrine), aggressive rhetoric (''Evil Empire''), and refusal to negotiate from perceived weakness.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-7', 'What was the Reagan Doctrine?', 'US policy of supporting anti-communist guerrillas and movements worldwide: Mujahideen in Afghanistan, Contras in Nicaragua, UNITA in Angola, and others. It represented a shift from containment to actively ''rolling back'' communism.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-7', 'What was the Euromissile Crisis?', 'In 1977, the USSR deployed SS-20 intermediate-range missiles targeting Western Europe. NATO responded with a ''dual-track'' decision (1979): negotiate removal while deploying US Pershing II and cruise missiles. This triggered massive peace protests and heightened tensions.', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-cold-fc-8', '8. Gorbachev and the End of the Cold War (1985-1991)', '#6B8BA3', 'P2-COLD', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-8', 'What was Glasnost?', 'Gorbachev''s policy of ''openness'' (from 1986): allowing greater freedom of speech, press freedom, release of political prisoners, and public discussion of Soviet problems. Intended to revitalise the system, it unleashed forces that ultimately destroyed it.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-8', 'What was Perestroika?', 'Gorbachev''s policy of ''restructuring'' the Soviet economy: introducing limited market mechanisms, reducing central planning, allowing cooperatives, and encouraging enterprise autonomy. It failed to deliver economic improvement and created chaos as the old system collapsed without a new one replacing it.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-8', 'What was the Sinatra Doctrine?', 'Gorbachev''s foreign policy spokesman Gennady Gerasimov declared (1989) that Eastern European states could choose their own path - ''doing it their way'' (referencing Frank Sinatra). It signalled Soviet non-intervention, enabling the 1989 revolutions.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-8', 'What happened in 1989?', 'The ''Year of Miracles'': Poland (Solidarity wins elections), Hungary (opens border to Austria), East Germany (Berlin Wall falls, 9 November), Czechoslovakia (Velvet Revolution), Romania (violent overthrow of Ceausescu), Bulgaria (communist leadership replaced).', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-8', 'Why did the Berlin Wall fall?', 'East German government miscommunication (Schabowski''s press conference, 9 Nov 1989), mass protests, Gorbachev''s refusal to use force, opening of Hungarian border allowing East German emigration, and general collapse of communist authority.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-8', 'What caused the collapse of the USSR (December 1991)?', 'Gorbachev''s reforms (glasnost/perestroika) unleashed nationalist movements, the failed August 1991 coup weakened central authority, Boris Yeltsin''s Russian Republic asserted sovereignty, and Soviet republics declared independence. The USSR was formally dissolved on 25 December 1991.', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-8', 'What was the INF Treaty (1987)?', 'Signed by Reagan and Gorbachev, it eliminated all intermediate-range nuclear missiles (500-5500 km). It was the first treaty to actually reduce nuclear arsenals rather than limit growth, and marked a breakthrough in arms control.', 7);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-cold-fc-9', '9. Cold War Crises in Europe: Hungary, Czechoslovakia, Poland', '#6B8BA3', 'P2-COLD', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-9', 'What was the Hungarian Uprising (1956)?', 'Hungarian people rose against Soviet-imposed communist rule, demanding reforms. Prime Minister Imre Nagy declared neutrality and withdrawal from the Warsaw Pact. The USSR invaded with 200,000 troops and 4,000 tanks, killing ~2,500 Hungarians. Nagy was executed in 1958.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-9', 'What was the Prague Spring (1968)?', 'Czechoslovak leader Alexander Dubcek introduced ''socialism with a human face'': press freedom, political liberalisation, economic reform. The USSR and Warsaw Pact invaded in August 1968, ending the reforms and installing a compliant government.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-9', 'What was the Brezhnev Doctrine?', 'Declared after the Prague Spring invasion: the USSR had the right to intervene in any socialist state where socialism was threatened. It justified Soviet control over Eastern Europe until Gorbachev effectively abandoned it (Sinatra Doctrine).', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-9', 'What was Solidarity (Poland)?', 'Founded in 1980 by Lech Walesa at the Gdansk shipyard, Solidarity was the first independent trade union in the Soviet bloc. It represented a mass movement of 10 million members. Martial law was imposed (1981) but Solidarity survived underground and won elections in 1989.', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-cold-fc-10', '10. The Sino-Soviet Split and Cold War Alliances', '#6B8BA3', 'P2-COLD', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-10', 'What caused the Sino-Soviet Split?', 'Ideological disagreements (Mao vs. Khrushchev over de-Stalinisation, peaceful coexistence), national rivalry (border disputes), Chinese resentment of Soviet patronage, competition for leadership of the communist world, and personal animosity between leaders.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-10', 'What was the significance of the Sino-Soviet Split?', 'It shattered communist unity, created a strategic triangle (US-USSR-China), enabled Nixon''s China opening (1972), complicated Cold War alliances, led to Sino-Soviet border clashes (1969), and benefited US diplomacy.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-10', 'What was NATO?', 'North Atlantic Treaty Organisation (est. 1949): Western military alliance based on collective defence (Article 5). Original 12 members grew to include West Germany (1955). It was the cornerstone of Western defence against the Soviet bloc.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-10', 'What was the Warsaw Pact?', 'Eastern bloc military alliance (est. 1955) in response to West German NATO membership. Led by the USSR, it included Poland, East Germany, Czechoslovakia, Hungary, Romania, Bulgaria, and Albania. It was dissolved in 1991.', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-cold-fc-11', '11. Social, Cultural, and Ideological Dimensions of the Cold War', '#6B8BA3', 'P2-COLD', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-11', 'How did the Cold War affect domestic politics?', 'McCarthyism in the US (Red Scare, blacklisting), Soviet ideological conformity, loyalty oaths, censorship, surveillance (FBI, KGB), nuclear anxiety, civil defence (duck and cover), and political polarisation in both blocs.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-11', 'What was the Space Race?', 'US-Soviet competition in space exploration: Sputnik (1957), Gagarin first in space (1961), Kennedy''s moon pledge, Apollo 11 moon landing (1969). It was both a propaganda tool and genuine scientific achievement, demonstrating technological superiority.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-11', 'How was the Cold War fought culturally?', 'Through propaganda, cultural diplomacy (jazz tours, ballet exchanges), sports competition (Olympics boycotts 1980/1984), film, literature, radio broadcasting (Voice of America, Radio Free Europe), and competing visions of modernity and progress.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-cold-fc-11', 'What was the ''Kitchen Debate'' (1959)?', 'An impromptu exchange between Nixon and Khrushchev at a Moscow exhibition over the merits of capitalism vs. communism, using a model American kitchen as the setting. It symbolised the Cold War''s ideological competition extending to consumer goods and daily life.', 4);

