-- Written questions (15 marks)
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-126', '1. Origins of the Cold War (1945-1947)', 'SL/HL', 'short_answer', 'P2-COLD', 15, 'Evaluate the relative importance of ideological differences and geopolitical interests in the origins of the Cold War.', '• Band 5 (13-15): Balanced evaluation of ideology (capitalism vs. communism, democracy vs. one-party rule) vs. geopolitics (security concerns, spheres of influence, balance of power) with specific evidence. Ideological: incompatible visions of post-war order, mutual demonisation, propaganda, universalist claims of both systems. Geopolitical: Soviet security concerns (buffer states after two German invasions), US economic interests (open markets), power vacuum in Europe, atomic monopoly.
• Must consider historiographical perspectives: orthodox (Soviet aggression), revisionist (US economic imperialism), post-revisionist (mutual responsibility).
• Band 3 (7-9): Some analysis but may overemphasise one factor.
• Band 1 (1-3): Vague generalisations without specific evidence.', 127);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-127', '1. Origins of the Cold War (1945-1947)', 'SL/HL', 'short_answer', 'P2-COLD', 15, 'To what extent was the Cold War inevitable by 1947?', '• Band 5 (13-15): Evaluative argument considering structural factors (ideological incompatibility, power vacuum) vs. contingent decisions (Truman Doctrine, Marshall Plan rejection, Berlin). Arguments for inevitability: deep ideological divide, mutual suspicion since 1917, wartime alliance was temporary. Arguments against: cooperation at Yalta showed compromise was possible, different leaders might have acted differently, economic interdependence could have been developed.
• Must reach clear, substantiated judgement.
• Band 3 (7-9): Narrative of events without clear evaluation of inevitability.
• Band 1 (1-3): Minimal relevant knowledge.', 128);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-128', '2. Berlin and the German Question (1948-1961)', 'SL/HL', 'short_answer', 'P2-COLD', 15, 'Evaluate the significance of Berlin as a source of Cold War tension between 1948 and 1961.', '• Band 5 (13-15): Chronological analysis of Berlin crises (Blockade 1948-49, Khrushchev''s ultimatum 1958, Wall 1961) with evaluation of their significance for broader Cold War dynamics. Blockade: led to NATO, solidified German division, demonstrated Western resolve. 1958 ultimatum: Khrushchev demanded Western withdrawal; raised tensions but no resolution. Wall (1961): ended crisis but became propaganda disaster; symbol of Cold War; stabilised GDR.
• Must evaluate: Was Berlin the most dangerous flashpoint? How did it shape Cold War dynamics?
• Band 3 (7-9): Narrative of events without full evaluation of significance.
• Band 1 (1-3): Vague; cannot detail specific Berlin crises.', 129);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-129', '3. The Nuclear Arms Race and Deterrence', 'SL/HL', 'short_answer', 'P2-COLD', 15, 'To what extent did the nuclear arms race increase or decrease the risk of war during the Cold War?', '• Band 5 (13-15): Balanced evaluation of stabilising effects (MAD deterrence, avoiding direct conflict) vs. destabilising effects (arms race, near-misses, proliferation, proxy wars) with specific evidence. Stabilising: MAD prevented direct superpower war, crises were resolved without nuclear use, arms control negotiations. Destabilising: Cuban Missile Crisis near-miss, accidental launch risks, arms race costs, nuclear proliferation, proxy wars as substitute.
• Must weigh evidence and reach a clear judgement.
• Band 3 (7-9): Some relevant analysis but may be one-sided.
• Band 1 (1-3): Vague with no specific evidence.', 130);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-130', '4. The Cuban Missile Crisis (1962)', 'SL/HL', 'short_answer', 'P2-COLD', 15, 'Evaluate the significance of the Cuban Missile Crisis for the development of the Cold War.', '• Band 5 (13-15): Detailed evaluation of the crisis''s impact on superpower relations, nuclear policy, and Cold War dynamics with specific evidence. Immediate: hotline, LTBT, recognition of mutual vulnerability, crisis management protocols. Longer-term: contributed to detente, arms control negotiations, both sides more cautious, Khrushchev weakened. Limitations: Cold War continued, arms race accelerated (both sides built up after the scare), proxy conflicts continued.
• Must evaluate the extent to which the crisis was a genuine turning point.
• Band 3 (7-9): Some relevant analysis but limited evaluation of long-term significance.
• Band 1 (1-3): Minimal knowledge of consequences.', 131);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-131', '5. Detente (1969-1979)', 'SL/HL', 'short_answer', 'P2-COLD', 15, 'To what extent was detente a success in reducing Cold War tensions?', '• Band 5 (13-15): Balanced evaluation of achievements and limitations of detente with specific evidence. Successes: SALT I, improved communications, reduced nuclear risk, trade expansion, Helsinki process, China opening. Limitations: arms race continued (qualitative improvements), proxy conflicts persisted (Angola, Horn of Africa), human rights violations continued, detente''s collapse showed fragility, mistrust never fully overcome.
• Must offer clear judgement on ''to what extent''.
• Band 3 (7-9): Some relevant analysis but may not fully evaluate.
• Band 1 (1-3): Vague; cannot identify specific achievements or failures.', 132);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-132', '6. Cold War in Asia, Latin America, and Africa (Proxy Conflicts)', 'SL/HL', 'short_answer', 'P2-COLD', 15, 'Evaluate the impact of the Cold War on one region of the developing world.', '• Band 5 (13-15): Detailed evaluation of superpower competition''s impact on a specific region (Latin America, Southeast Asia, Africa, Middle East) with specific examples.
• For Latin America: US interventions (Guatemala, Chile, Nicaragua), Cuban Revolution, Alliance for Progress, support for dictators, economic impact.
• For Africa: proxy wars (Angola, Ethiopia), support for regimes, complication of decolonisation, economic aid with strings.
• Must evaluate both positive (aid, development) and negative (conflict, instability, authoritarianism) impacts.
• Band 3 (7-9): Some relevant examples but limited evaluation.
• Band 1 (1-3): Vague; cannot identify specific regional impacts.', 133);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-133', '7. The Second Cold War and Reagan (1979-1985)', 'SL/HL', 'short_answer', 'P2-COLD', 15, 'To what extent was Reagan responsible for ending the Cold War?', '• Band 5 (13-15): Balanced evaluation of Reagan''s role against other factors with specific evidence. Reagan''s contribution: military pressure forced USSR to overspend, SDI threat, rhetoric challenged Soviet legitimacy, willingness to negotiate with Gorbachev.
• Other factors: inherent Soviet economic/political weaknesses, Gorbachev''s reforms (glasnost, perestroika), Eastern European peoples'' agency, long-term structural decline of communism.
• Must weigh multiple factors and reach clear judgement.
• Band 3 (7-9): May overemphasise Reagan or neglect other factors.
• Band 1 (1-3): One-sided or factually inaccurate.', 134);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-134', '8. Gorbachev and the End of the Cold War (1985-1991)', 'SL/HL', 'short_answer', 'P2-COLD', 15, 'Evaluate the reasons for the end of the Cold War.', '• Band 5 (13-15): Multi-factor evaluation including Gorbachev, Reagan, structural Soviet weakness, Eastern European agency, and economic factors. Gorbachev: glasnost, perestroika, Sinatra Doctrine, willingness to negotiate, personal chemistry with Reagan/Bush. Reagan: military pressure, SDI, rhetoric, but also willingness to negotiate. Structural factors: Soviet economic stagnation, technology gap, Afghan War costs, nationalist movements. Eastern European agency: Solidarity, mass protests, civil society, 1989 revolutions.
• Must weigh multiple factors and reach a clear judgement.
• Band 3 (7-9): May focus on one factor (usually Gorbachev or Reagan).
• Band 1 (1-3): Oversimplified one-cause explanation.', 135);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-135', '8. Gorbachev and the End of the Cold War (1985-1991)', 'SL/HL', 'short_answer', 'P2-COLD', 15, 'To what extent were the 1989 revolutions in Eastern Europe the result of Gorbachev''s policies?', '• Band 5 (13-15): Balanced evaluation of Gorbachev''s role (glasnost, Sinatra Doctrine, non-intervention) vs. domestic factors (popular movements, economic failure, dissident networks) with specific evidence from multiple countries. Gorbachev''s role: signalled non-intervention, glasnost inspired reformers, perestroika model encouraged change. Domestic factors: Solidarity in Poland (founded 1980), Hungarian reform communists, East German mass protests, Czechoslovak Charter 77/Vaclav Havel, Romanian anti-Ceausescu uprising. Long-term factors: communist systems'' inherent weaknesses, economic stagnation, loss of ideological legitimacy.
• Must evaluate using evidence from specific 1989 revolutions.
• Band 3 (7-9): Some relevant analysis but may not evaluate multiple countries.
• Band 1 (1-3): Vague; cannot discuss specific revolutions.', 136);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-136', '9. Cold War Crises in Europe: Hungary, Czechoslovakia, Poland', 'SL/HL', 'short_answer', 'P2-COLD', 15, 'Compare Soviet responses to challenges to its authority in Eastern Europe during the Cold War.', '• Band 5 (13-15): Systematic comparison of at least two crises (Hungary 1956, Czechoslovakia 1968, Poland 1980-81, 1989) analysing methods, motivations, and outcomes. 1956: military invasion, execution of Nagy, restoration of hardline rule. 1968: Warsaw Pact invasion, Brezhnev Doctrine, normalisation. 1980-81: martial law (Polish army, not Soviet), Solidarity suppressed but survived. 1989: Gorbachev''s non-intervention, peaceful revolutions.
• Must analyse WHY responses differed and their significance.
• Band 3 (7-9): Some comparison but may not fully analyse differences.
• Band 1 (1-3): Cannot detail specific crises.', 137);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-137', '10. The Sino-Soviet Split and Cold War Alliances', 'SL/HL', 'short_answer', 'P2-COLD', 15, 'Evaluate the impact of the Sino-Soviet Split on the development of the Cold War.', '• Band 5 (13-15): Detailed evaluation of how the Split changed Cold War dynamics (alliance structures, US diplomacy, proxy conflicts, arms race) with specific evidence. Impact: shattered communist unity, enabled Nixon''s China opening, created triangular diplomacy, complicated Third World conflicts (China and USSR backed different factions), border clashes raised new tensions. Limitations: Cold War continued as bipolar contest; Split did not end superpower rivalry; detente had other causes too.
• Must evaluate the relative significance of the Split.
• Band 3 (7-9): Some relevant analysis but may not fully evaluate impact.
• Band 1 (1-3): Vague; cannot explain the Split''s consequences.', 138);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-138', '11. Social, Cultural, and Ideological Dimensions of the Cold War', 'SL/HL', 'short_answer', 'P2-COLD', 15, 'To what extent was the Cold War an ideological conflict rather than a geopolitical one?', '• Band 5 (13-15): Balanced evaluation considering both ideological dimensions (capitalism vs. communism, propaganda, cultural competition) and geopolitical dimensions (balance of power, spheres of influence, resource competition). Ideological: competing universalist claims, propaganda, cultural diplomacy, domestic political impact (McCarthyism), Space Race as ideological competition. Geopolitical: security concerns, power projection, proxy wars for strategic advantage, economic competition, alliance systems.
• Strong answers argue these dimensions were inseparable: ideology shaped geopolitical interests and vice versa.
• Band 3 (7-9): May overemphasise one dimension.
• Band 1 (1-3): Cannot distinguish between ideological and geopolitical factors.', 139);

