-- Flashcard topics & cards
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-demo-fc-1', '1. Conditions for the Emergence of Democratic States', '#6BA37B', 'P2-DEMO', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-1', 'What conditions favour the emergence of democracy?', 'Economic development and a strong middle class, literacy and education, a tradition of rule of law, experience with civil society organisations, weakened authoritarian regimes, and external pressure or support for democratisation.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-1', 'What is Lipset''s modernisation theory?', 'Seymour Martin Lipset argued that economic development (urbanisation, industrialisation, education) creates conditions favourable for democracy by expanding the middle class and promoting political participation.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-1', 'How did WWI contribute to democratisation?', 'The collapse of empires (Ottoman, Austro-Hungarian, Russian, German) created new states, many initially adopting democratic constitutions. Wilson''s Fourteen Points promoted self-determination and democratic governance.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-1', 'How did WWII affect democratisation?', 'The defeat of fascist regimes led to democratisation in Germany, Italy, and Japan under Allied occupation. The war discredited authoritarian ideologies and strengthened democratic norms internationally.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-1', 'What role do constitutions play in democratic emergence?', 'Constitutions establish the framework for democratic governance: separation of powers, protection of rights, rule of law, electoral processes, and limits on executive authority. The Weimar Constitution (1919) and India''s Constitution (1950) are key examples.', 5);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-demo-fc-2', '2. Case Study: The Weimar Republic (1919-1933)', '#6BA37B', 'P2-DEMO', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-2', 'Why was the Weimar Republic established?', 'After Germany''s defeat in WWI and the abdication of Kaiser Wilhelm II in November 1918, a republic was proclaimed. The Weimar Constitution (August 1919) created a democratic parliamentary system with proportional representation.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-2', 'What were the weaknesses of the Weimar Constitution?', 'Article 48 (emergency powers for the President), proportional representation (leading to coalition instability), the ''stab in the back'' myth undermining legitimacy, and lack of democratic tradition in Germany.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-2', 'What was the ''stab in the back'' myth?', 'The false belief promoted by right-wing nationalists that Germany''s WWI defeat was caused by treasonous civilians (Jews, socialists, democrats) rather than military failure. It delegitimised the Weimar government as ''November criminals''.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-2', 'How did economic crises threaten Weimar democracy?', 'Hyperinflation (1923) destroyed middle-class savings; the brief Golden Age (1924-29) brought stability via US loans; the Great Depression (1929) caused mass unemployment (6 million by 1932) and radicalised politics.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-2', 'What was the Dawes Plan (1924)?', 'An American-brokered plan that restructured Germany''s reparations payments, provided US loans, and stabilised the German economy, ushering in the ''Golden Age'' of Weimar (1924-29).', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-2', 'How did Hitler come to power legally?', 'Through electoral gains (NSDAP became largest party by July 1932), backroom political deals (Papen and Hindenburg appointed Hitler Chancellor on 30 Jan 1933), and subsequent use of the Reichstag Fire and Enabling Act to dismantle democracy.', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-2', 'What was the Enabling Act (March 1933)?', 'Passed after the Reichstag Fire, it gave Hitler power to enact laws without Reichstag approval for four years, effectively ending Weimar democracy and establishing Nazi dictatorship.', 7);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-demo-fc-3', '3. Case Study: India''s Democratic Development', '#6BA37B', 'P2-DEMO', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-3', 'What were the key features of India''s 1950 Constitution?', 'Federal structure with strong centre, parliamentary democracy, universal adult suffrage, fundamental rights, directive principles of state policy, independent judiciary, and secular state. It was the world''s longest written constitution.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-3', 'How did Nehru shape Indian democracy (1947-64)?', 'Nehru established democratic norms, promoted secularism, built institutions (Planning Commission, IITs), pursued non-alignment, implemented Five-Year Plans for economic development, and maintained parliamentary governance despite pressures.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-3', 'What challenges did Indian democracy face?', 'Communal violence (Hindu-Muslim tensions), linguistic diversity (States Reorganisation Act 1956), caste discrimination, poverty, regional separatism, and balancing centralisation with federalism.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-3', 'What was the Emergency (1975-77)?', 'Prime Minister Indira Gandhi declared a state of emergency, suspending civil liberties, censoring the press, imprisoning political opponents, and ruling by decree. It was the most serious threat to Indian democracy and ended with her electoral defeat in 1977.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-3', 'How did India''s democracy survive the Emergency?', 'Free elections were held in 1977 despite authoritarian rule; voters rejected Indira Gandhi decisively; the judiciary maintained some independence; press resistance and civil society mobilised; democratic norms proved resilient.', 5);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-demo-fc-4', '4. Case Study: USA - Expansion of Democracy', '#6BA37B', 'P2-DEMO', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-4', 'How did the US Constitution establish democracy?', 'The 1787 Constitution created a federal republic with separation of powers (executive, legislative, judicial), checks and balances, Bill of Rights (1791), and limited government. However, suffrage was initially restricted to white male property owners.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-4', 'How was suffrage expanded in the USA?', '15th Amendment (1870) - race; 19th Amendment (1920) - women; 24th Amendment (1964) - abolished poll taxes; Voting Rights Act (1965) - enforcement of Black voting rights; 26th Amendment (1971) - lowered voting age to 18.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-4', 'What was the Civil Rights Movement?', 'A mass movement (1950s-60s) led by figures like Martin Luther King Jr., Rosa Parks, and others that used non-violent protest to end racial segregation and secure voting rights for African Americans, culminating in the Civil Rights Act (1964) and Voting Rights Act (1965).', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-4', 'What was the New Deal?', 'FDR''s program (1933-39) of government intervention to combat the Great Depression through relief, recovery, and reform. It expanded federal power, created the welfare state, and reshaped American democracy by bringing government closer to citizens'' economic lives.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-4', 'What was McCarthyism?', 'Senator Joseph McCarthy''s anti-communist campaign (1950-54) that led to widespread persecution of suspected communists, blacklisting, and violations of civil liberties. It represented a significant threat to democratic freedoms during the Cold War.', 5);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-demo-fc-5', '5. Case Study: Post-WWII Japan''s Democratisation', '#6BA37B', 'P2-DEMO', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-5', 'How was Japan democratised after WWII?', 'Under US occupation led by General MacArthur (1945-52), Japan adopted a new constitution (1947) that established parliamentary democracy, renounced war (Article 9), guaranteed civil liberties, instituted land reform, broke up zaibatsu, and reduced the Emperor to a symbolic role.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-5', 'What was Article 9 of the Japanese Constitution?', 'The ''peace clause'' by which Japan renounced war as a sovereign right and pledged not to maintain military forces. It was a unique democratic experiment, though later reinterpreted to allow Self-Defense Forces.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-5', 'How did land reform support democracy?', 'MacArthur''s land reform (1946-50) redistributed land from absentee landlords to tenant farmers, creating a rural middle class with a stake in the democratic system and reducing the power of the old elite.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-5', 'What was the ''1955 System''?', 'The dominance of the Liberal Democratic Party (LDP) from 1955 onwards, creating essentially one-party rule within a democratic framework. The LDP governed Japan almost continuously until the 1990s.', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-demo-fc-6', '6. Case Study: South Africa''s Transition to Democracy', '#6BA37B', 'P2-DEMO', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-6', 'What was apartheid?', 'A system of institutionalised racial segregation in South Africa (1948-1994) enforced by the National Party. It classified people by race, restricted non-white rights, created bantustans, and maintained white minority rule.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-6', 'How did apartheid end?', 'Through a combination of internal resistance (ANC, UDF, township uprisings), international sanctions, economic pressure, the end of the Cold War (removing communist threat justification), and negotiations led by de Klerk and Mandela from 1990.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-6', 'What was the role of Nelson Mandela?', 'ANC leader imprisoned 1964-1990, Mandela became the symbol of anti-apartheid resistance. After release, he negotiated the transition to democracy, won the 1994 election (first fully democratic), and promoted reconciliation over retribution.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-6', 'What challenges did post-apartheid South Africa face?', 'Massive economic inequality, high unemployment, HIV/AIDS crisis, crime, corruption, land reform debates, service delivery failures, and maintaining racial reconciliation while addressing historical injustice.', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-demo-fc-7', '7. Democratic Principles: Suffrage, Representation, and Rights', '#6BA37B', 'P2-DEMO', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-7', 'What are the key principles of liberal democracy?', 'Free and fair elections, universal suffrage, rule of law, protection of individual rights and civil liberties, separation of powers, independent judiciary, free press, multi-party system, and accountability of government to citizens.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-7', 'How has suffrage expanded globally in the 20th century?', 'From restricted (property-owning males) to universal: women''s suffrage (NZ 1893, UK 1928, France 1944, Switzerland 1971); racial inclusion (US Voting Rights Act 1965, SA 1994); age lowered (18 in most democracies by 1970s).', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-7', 'What is the difference between direct and representative democracy?', 'Direct democracy: citizens vote directly on laws (referendums, Swiss cantons). Representative democracy: citizens elect representatives to make decisions (most modern democracies). Most states use a combination.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-7', 'What role does the judiciary play in democracy?', 'An independent judiciary protects constitutional rights, checks executive/legislative power, resolves disputes, ensures rule of law, and can strike down unconstitutional laws (judicial review). Examples: US Supreme Court, Indian Supreme Court.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-7', 'What are threats to democracy?', 'Populism, erosion of press freedom, corruption, voter suppression, gerrymandering, economic inequality limiting political participation, concentration of media ownership, and the rise of authoritarian tendencies within democratic systems.', 5);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-demo-fc-8', '8. Role of Political Parties, Elections, and Civil Society', '#6BA37B', 'P2-DEMO', 8);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-8', 'What role do political parties play in democracy?', 'Parties aggregate interests, present policy platforms, mobilise voters, recruit leaders, form governments, provide opposition/accountability, and give citizens structured political choices. Multi-party systems are considered essential for healthy democracy.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-8', 'What is the difference between a two-party and multi-party system?', 'Two-party (US, UK): two dominant parties compete; tends to produce stable majority governments but limits voter choice. Multi-party (India, Germany): many parties compete; often requires coalition governments but offers broader representation.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-8', 'What is civil society and why is it important for democracy?', 'Civil society consists of voluntary associations, NGOs, trade unions, religious organisations, and community groups that operate independently of government. They hold government accountable, promote participation, and protect citizens'' interests.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-8', 'How do electoral systems affect democracy?', 'First-past-the-post (FPTP): simple, produces strong governments but underrepresents minorities. Proportional representation (PR): more representative but can cause coalition instability. Mixed systems attempt to combine benefits of both.', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-demo-fc-9', '9. Economic and Social Policies in Democratic States', '#6BA37B', 'P2-DEMO', 9);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-9', 'How did the welfare state develop in democracies?', 'Post-WWII, many democracies established welfare states providing healthcare, education, pensions, unemployment benefits, and housing. Key examples: UK (Beveridge Report, NHS 1948), USA (New Deal, Great Society), Scandinavian social democracy.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-9', 'What was the Great Society program?', 'President Lyndon Johnson''s domestic agenda (1964-68) that expanded welfare, created Medicare and Medicaid, passed civil rights legislation, and launched the ''War on Poverty''. It represented a major expansion of government''s role in addressing social inequality.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-9', 'How have democracies addressed inequality?', 'Through progressive taxation, welfare programs, education expansion, affirmative action, minimum wage laws, healthcare provision, and civil rights legislation. Success has varied significantly between states.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-9', 'What tensions exist between capitalism and democracy?', 'Economic inequality can undermine political equality (wealth buys influence); market failures may require government intervention; citizens may demand redistribution through democratic processes; corporate power may override democratic will.', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-demo-fc-10', '10. Consolidation, Erosion, and Threats to Democracy', '#6BA37B', 'P2-DEMO', 10);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-10', 'What is democratic consolidation?', 'The process by which a democracy becomes stable and self-sustaining, where democratic norms are widely accepted, institutions are strong, no significant groups seek to overthrow the system, and democracy becomes ''the only game in town'' (Linz and Stepan).', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-10', 'What factors can lead to democratic erosion?', 'Economic crises, populist leaders undermining institutions, corruption, weakening of press freedom, politicisation of the judiciary, ethnic/religious polarisation, external threats, and gradual dismantling of checks and balances.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-10', 'What is the ''third wave'' of democratisation?', 'Samuel Huntington''s concept describing the wave of transitions to democracy beginning in the mid-1970s (Portugal 1974), spreading through Southern Europe, Latin America, East Asia, and Eastern Europe after the Cold War.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-10', 'How did the end of the Cold War affect democracy?', 'The collapse of communism (1989-91) led to democratic transitions across Eastern Europe and the former Soviet Union. Francis Fukuyama argued it represented the ''end of history'' with liberal democracy triumphant, though this proved premature.', 4);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-demo-fc-11', '11. Comparative Analysis: Democratic Transitions', '#6BA37B', 'P2-DEMO', 11);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-11', 'What types of democratic transition exist?', 'Revolution from below (people overthrow regime), negotiated transition (elites and opposition agree on reforms, e.g., South Africa), reform from above (existing leaders initiate change, e.g., Gorbachev), and imposed democracy (foreign occupation, e.g., post-WWII Japan/Germany).', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-11', 'How do transitions from authoritarian to democratic rule differ?', 'Key variables: whether the transition is violent or peaceful, negotiated or imposed, gradual or sudden, and whether the old regime''s elites retain power. These differences affect the quality and durability of the resulting democracy.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-11', 'What is the role of leadership in democratic transitions?', 'Visionary leaders can negotiate transitions (Mandela, de Klerk), build democratic institutions (Nehru), resist authoritarian temptations (Washington), or undermine democracy from within (Weimar politicians). Leadership quality is often cited as crucial.', 3);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-demo-fc-12', '12. Media, Gender, and Minority Rights in Democracies', '#6BA37B', 'P2-DEMO', 12);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-12', 'Why is a free press essential for democracy?', 'A free press informs citizens, holds government accountable (watchdog function), provides a forum for debate, exposes corruption, and enables informed political participation. Restrictions on press freedom are a key indicator of democratic erosion.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-12', 'How have democracies addressed gender equality?', 'Through women''s suffrage (progressive expansion across 20th century), equal pay legislation, anti-discrimination laws, maternity protections, quotas for political representation, and addressing gender-based violence. Progress has been uneven across democracies.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-12', 'How have democracies addressed minority rights?', 'Through constitutional protections, anti-discrimination legislation (e.g., US Civil Rights Act 1964), affirmative action, multicultural policies, indigenous rights recognition, and international human rights frameworks. Tensions between majority rule and minority rights remain a core democratic challenge.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-demo-fc-12', 'What is the tension between majority rule and minority rights?', 'Democracy requires majority decision-making, but unchecked majority power can oppress minorities (tyranny of the majority). Constitutional protections, independent courts, and human rights norms aim to balance majority rule with minority rights.', 4);

-- MCQ questions
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-324', '1. Conditions for the Emergence of Democratic States', 'SL/HL', 'P2-DEMO', 'Lipset''s modernisation theory argues that democracy is most likely when:', 'A strong military exists', 'Economic development creates a middle class', 'A single dominant party controls politics', 'Foreign powers impose democratic institutions', 1, 'See mark scheme for detailed explanation.', 325);
