-- Written questions (15 marks)
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-139', '1. Conditions for the Emergence of Democratic States', 'SL/HL', 'short_answer', 'P2-DEMO', 15, 'Examine the conditions that led to the emergence of democracy in two states, each from a different region.', '• Band 5 (13-15): Detailed comparative analysis of conditions (political, economic, social, external) in two states from different regions with specific evidence.
• Examples: Weimar Germany (post-WWI collapse of monarchy, revolution, new constitution) vs. India (anti-colonial movement, educated elite, British parliamentary traditions, 1950 Constitution).
• Or: Post-WWII Japan (Allied occupation, MacArthur''s reforms, land reform) vs. South Africa (end of apartheid, Mandela, negotiated transition, 1996 Constitution).
• Must analyse WHY these conditions favoured democracy, not just list them.
• Band 3 (7-9): Descriptive account with some analysis; limited genuine comparison.
• Band 1 (1-3): Vague generalisations without specific case study evidence.', 140);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-140', '2. Case Study: The Weimar Republic (1919-1933)', 'SL/HL', 'short_answer', 'P2-DEMO', 15, 'To what extent was the collapse of the Weimar Republic inevitable?', '• Band 5 (13-15): Balanced evaluative argument considering structural weaknesses, economic crises, political failures, and contingent factors. Arguments for inevitability: constitutional flaws (Article 48, PR), lack of democratic tradition, Treaty of Versailles burden, ''stab in the back'' myth, anti-democratic elites. Arguments against: The Golden Age showed stability was possible; specific contingencies (Wall Street Crash, Hindenburg''s decisions, backroom deals) were not predetermined.
• Must provide specific evidence and reach a clear, substantiated judgement.
• Band 3 (7-9): Narrative of events with some analysis; may lack balanced evaluation.
• Band 1 (1-3): Generalised; no clear argument or specific evidence.', 141);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-141', '2. Case Study: The Weimar Republic (1919-1933)', 'SL/HL', 'short_answer', 'P2-DEMO', 15, 'Evaluate the impact of economic factors on the development of democracy in Weimar Germany.', '• Band 5 (13-15): Detailed analysis of economic factors (hyperinflation, Dawes Plan recovery, Great Depression) and their political consequences, evaluated against non-economic factors. Hyperinflation (1923): eroded middle-class trust; Dawes Plan/Golden Age (1924-29): brief democratic stability; Great Depression (1929+): mass unemployment, radicalisation, rise of extremism.
• Non-economic factors: constitutional weaknesses, political culture, role of elites, propaganda, leadership failures.
• Strong answers evaluate the RELATIVE importance of economic vs. other factors.
• Band 3 (7-9): Descriptive with some analysis; may not fully evaluate relative importance.
• Band 1 (1-3): Minimal relevant knowledge.', 142);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-142', '3. Case Study: India''s Democratic Development', 'SL/HL', 'short_answer', 'P2-DEMO', 15, 'To what extent has India been successful in maintaining democracy since independence?', '• Band 5 (13-15): Balanced evaluation weighing successes (regular elections, peaceful transfers of power, constitutional governance, vibrant civil society) against challenges (Emergency, communal violence, corruption, inequality). Successes: world''s largest democracy, regular free elections since 1952, peaceful transfer of power, independent judiciary, free press, multi-party system. Challenges: Emergency (1975-77), communal riots (1984 anti-Sikh, 2002 Gujarat), caste discrimination, corruption, regional separatism, poverty limiting political participation.
• Must reach a clear judgement on ''to what extent'' with specific evidence.
• Band 3 (7-9): Some relevant analysis but may be one-sided or lack specific evidence.
• Band 1 (1-3): Generalised claims without substantiation.', 143);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-143', '4. Case Study: USA - Expansion of Democracy', 'SL/HL', 'short_answer', 'P2-DEMO', 15, 'Evaluate the extent to which the USA achieved full democracy by 1970.', '• Band 5 (13-15): Evaluative argument weighing democratic achievements against persistent limitations with specific evidence. Achievements: universal suffrage (19th, 24th, 26th Amendments), Civil Rights Act, Voting Rights Act, free press, separation of powers, New Deal expansion of rights. Limitations: continued racial inequality, McCarthyism legacy, socio-economic barriers to participation, gerrymandering, Cold War security state, Vietnam War and trust in government.
• Must define ''full democracy'' and offer clear judgement on extent achieved.
• Band 3 (7-9): Some relevant knowledge but limited evaluation.
• Band 1 (1-3): Vague or inaccurate with no clear argument.', 144);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-144', '5. Case Study: Post-WWII Japan''s Democratisation', 'SL/HL', 'short_answer', 'P2-DEMO', 15, 'To what extent was Japan''s post-WWII democratisation imposed from outside rather than emerging from within?', '• Band 5 (13-15): Balanced evaluation of external (US occupation, constitution-writing, reforms) vs. internal (pre-war democratic traditions, Taisho democracy, Japanese agency) factors. External: MacArthur''s directives, new constitution drafted by Americans, land reform, zaibatsu dissolution, war crimes trials, educational reforms. Internal: Taisho-era democratic movements, Japanese officials'' role in adapting reforms, popular support for peace constitution, pre-existing parliamentary traditions (Diet since 1890).
• Must offer clear judgement on ''to what extent'' with specific evidence.
• Band 3 (7-9): Descriptive with limited evaluation of the external/internal balance.
• Band 1 (1-3): Minimal knowledge; no clear argument.', 145);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-145', '6. Case Study: South Africa''s Transition to Democracy', 'SL/HL', 'short_answer', 'P2-DEMO', 15, 'Evaluate the role of leadership in the transition to democracy in South Africa.', '• Band 5 (13-15): Detailed evaluation of leadership (Mandela, de Klerk, Tutu) balanced against structural/external factors. Leadership: Mandela''s moral authority, reconciliation approach, willingness to negotiate; de Klerk''s decision to release Mandela and unban ANC; Tutu and the TRC.
• Other factors: mass resistance, economic sanctions, Cold War end, international pressure, economic crisis for white South Africans.
• Must evaluate the RELATIVE importance of leadership vs. other factors.
• Band 3 (7-9): Narrative of events with some analysis of leadership.
• Band 1 (1-3): Generalised; no specific evidence.', 146);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-146', '7. Democratic Principles: Suffrage, Representation, and Rights', 'SL/HL', 'short_answer', 'P2-DEMO', 15, 'Discuss the challenges to maintaining democratic rights and freedoms in the 20th century with reference to two states.', '• Band 5 (13-15): Detailed comparative discussion of challenges (internal and external) with specific evidence from two states. Challenges may include: McCarthyism in the USA, the Emergency in India, apartheid in South Africa, Weimar''s collapse, threats to press freedom, corruption, populism.
• Must discuss how states responded to these challenges and evaluate success.
• Strong answers consider whether challenges were overcome or remain ongoing.
• Band 3 (7-9): Some relevant analysis but limited comparison or specific evidence.
• Band 1 (1-3): Vague with no case study evidence.', 147);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-147', '8. Role of Political Parties, Elections, and Civil Society', 'SL/HL', 'short_answer', 'P2-DEMO', 15, 'Evaluate the role of political parties in the development of democracy in one state.', '• Band 5 (13-15): Detailed evaluation of how parties contributed to (or undermined) democratic development, with specific evidence. May discuss: party formation, opposition role, coalition dynamics, dominant party systems, party ideology and policies.
• Examples: INC in India (democratic consolidation but Emergency under Indira Gandhi); LDP in Japan (stability but one-party dominance); ANC in South Africa (democratic transition but corruption concerns).
• Must evaluate both positive and negative impacts of party politics.
• Band 3 (7-9): Some analysis but may be descriptive or one-sided.
• Band 1 (1-3): Minimal relevant knowledge.', 148);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-148', '9. Economic and Social Policies in Democratic States', 'SL/HL', 'short_answer', 'P2-DEMO', 15, 'Compare and contrast the social and economic policies of two democratic states.', '• Band 5 (13-15): Detailed, systematic comparison of policies (welfare, taxation, education, healthcare) with specific evidence and evaluation of effectiveness.
• Examples: USA (New Deal, Great Society, market-oriented) vs. UK (Beveridge welfare state, NHS, post-war consensus); or India (mixed economy, Five-Year Plans) vs. Japan (economic miracle, state-guided capitalism).
• Must show genuine comparison with similarities and differences.
• Strong answers evaluate the democratic implications of economic/social policies.
• Band 3 (7-9): Some comparison but may be descriptive or focus only on one state.
• Band 1 (1-3): Vague with no specific policy evidence.', 149);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-149', '10. Consolidation, Erosion, and Threats to Democracy', 'SL/HL', 'short_answer', 'P2-DEMO', 15, 'To what extent has democracy been successfully consolidated in one state you have studied?', '• Band 5 (13-15): Detailed evaluation of consolidation using specific criteria (free elections, peaceful transfers, rule of law, civil liberties, democratic norms) with evidence. May discuss: India (sustained democracy but challenges), Japan (stable but dominated by LDP), South Africa (democratic but inequality persists), Germany (strong post-war consolidation).
• Must consider both indicators of success and ongoing challenges.
• Strong answers define consolidation criteria and evaluate systematically.
• Band 3 (7-9): Some relevant analysis but may not define consolidation clearly.
• Band 1 (1-3): Generalised with no specific evidence.', 150);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-150', '11. Comparative Analysis: Democratic Transitions', 'SL/HL', 'short_answer', 'P2-DEMO', 15, 'Compare and contrast the transitions to democracy in two states, each from a different region.', '• Band 5 (13-15): Systematic comparison of transition type, process, key actors, and outcomes with specific evidence from two regions.
• Examples: South Africa (negotiated) vs. Japan (imposed); India (anti-colonial movement to democracy) vs. Germany (post-authoritarian reconstruction).
• Must compare: causes of transition, methods, role of leadership, constitutional frameworks, and outcomes.
• Strong answers evaluate which transition was more successful and why.
• Band 3 (7-9): Some comparison but may be implicit or focus disproportionately on one case.
• Band 1 (1-3): Vague; no genuine comparison.', 151);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-151', '12. Media, Gender, and Minority Rights in Democracies', 'SL/HL', 'short_answer', 'P2-DEMO', 15, 'Evaluate the extent to which democratic states have successfully protected the rights of minorities.', '• Band 5 (13-15): Evaluative argument with specific examples from at least two states, weighing successes against failures. Successes: Constitutional protections, civil rights legislation, affirmative action, multicultural policies, international human rights frameworks. Failures: Persistent discrimination, apartheid (South Africa pre-1994), Jim Crow (USA), indigenous dispossession, anti-minority violence.
• Must offer clear judgement on ''to what extent'' with specific evidence.
• Band 3 (7-9): Some relevant examples but limited evaluation.
• Band 1 (1-3): Generalised without specific evidence.', 152);

