-- Flashcard topics & cards
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-indp-fc-1', '1. Origins and Rise of Independence Movements', '#A39B6B', 'P2-INDP', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-indp-fc-1', 'What were the main intellectual influences on independence movements?', 'Enlightenment ideas (liberty, equality, natural rights), the American Revolution (1776), the French Revolution (1789), and nationalist philosophies emphasising self-determination.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-indp-fc-1', 'How did the Napoleonic Wars contribute to Latin American independence?', 'Napoleon''s 1808 invasion of Spain destabilised the Spanish monarchy, creating a power vacuum in the colonies. Creole elites seized the opportunity to establish juntas and assert autonomy.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-indp-fc-1', 'What role did socio-economic grievances play?', 'Colonial economic restrictions (mercantilist trade policies, heavy taxation), exclusion of Creoles from top political posts, and racial caste systems fuelled resentment against imperial rule.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-indp-fc-1', 'What was the Grito de Dolores (1810)?', 'Father Miguel Hidalgo''s call to arms in Mexico that launched the Mexican War of Independence. It rallied mestizos and indigenous people against Spanish colonial rule.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-indp-fc-1', 'How did colonial education contribute to nationalism?', 'Western-educated colonial elites encountered ideas of self-governance, democracy, and nationalism, which they applied to their own colonial contexts (e.g., Indian National Congress leaders, Ho Chi Minh).', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-indp-fc-1', 'How did WWI and WWII affect independence movements?', 'The wars weakened European powers economically and militarily, exposed the hypocrisy of colonial empires fighting for freedom abroad while denying it to colonies, and created opportunities for nationalist movements to press demands.', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-indp-fc-1', 'What was the impact of the Atlantic Charter (1941)?', 'Churchill and Roosevelt declared the right of all peoples to choose their own government. Colonised peoples used this to legitimise independence demands, even though the Allies did not intend it for colonies.', 7);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-indp-fc-2', '2. Methods Used and Reasons for Success', '#A39B6B', 'P2-INDP', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-indp-fc-2', 'What were the main methods used by independence movements?', 'Armed struggle/guerrilla warfare, non-violent resistance (boycotts, civil disobedience), political negotiation, propaganda/media campaigns, strikes and economic disruption, and diplomatic appeals to international community.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-indp-fc-2', 'What was Gandhi''s concept of Satyagraha?', 'A philosophy and practice of non-violent resistance meaning ''truth-force'' or ''soul-force''. It involved civil disobedience, non-cooperation, boycotts, and peaceful protest to resist British rule in India.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-indp-fc-2', 'How did guerrilla warfare contribute to independence?', 'Used by movements like Vietnam (Viet Minh), Cuba, Algeria (FLN), and Zimbabwe (ZANLA/ZIPRA). It was effective against stronger conventional forces by using terrain, local knowledge, and attrition to exhaust colonial powers.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-indp-fc-2', 'What was the role of international support?', 'External support was often crucial: Cold War superpowers backed different sides; the UN provided a forum for anti-colonial advocacy; diaspora communities provided funding; neighbouring states offered refuge and supply routes.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-indp-fc-2', 'Why did the British leave India in 1947?', 'Post-WWII economic exhaustion, the Quit India Movement, the Indian National Army, growing unrest (including the Royal Indian Navy mutiny), Labour government''s sympathy for decolonisation, and American/international pressure.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-indp-fc-2', 'What was the Mau Mau Uprising (1952-1960)?', 'An armed insurgency by the Kikuyu people against British colonial rule in Kenya. While militarily suppressed, the brutality of the British response drew international criticism and accelerated negotiations for Kenyan independence (1963).', 6);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-indp-fc-2', 'How did propaganda and media help movements?', 'Newspapers, pamphlets, radio, and later TV helped build nationalist consciousness, disseminate ideology, counter colonial narratives, and garner international sympathy (e.g., Ho Chi Minh''s appeals, Indian press during Salt March).', 7);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-indp-fc-2', 'What was the role of the United Nations in decolonisation?', 'The UN General Assembly Resolution 1514 (1960) declared colonialism a denial of human rights. The UN provided a global platform for colonised peoples to present their case and apply diplomatic pressure on colonial powers.', 8);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-indp-fc-3', '3. Challenges Faced in the First 10 Years', '#A39B6B', 'P2-INDP', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-indp-fc-3', 'What were common political challenges?', 'Building state institutions from scratch, managing ethnic/religious/regional divisions, choosing between democracy and authoritarian rule, writing constitutions, establishing legitimacy, and handling power struggles among independence leaders.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-indp-fc-3', 'What economic challenges did new states face?', 'Inherited colonial economic structures (mono-crop/resource dependency), lack of infrastructure, capital flight, need to diversify economies, brain drain, poverty, and often unfavourable trade terms with former colonial powers.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-indp-fc-3', 'Why was the Partition of India (1947) so devastating?', 'It caused the largest mass migration in history (10-15 million displaced), communal violence killing up to 2 million, the Kashmir conflict, economic disruption, and lasting India-Pakistan hostility.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-indp-fc-3', 'What were the challenges of nation-building in Africa?', 'Arbitrary colonial borders cut across ethnic groups, creating multi-ethnic states with weak national identity. This led to ethnic tensions, secessionist movements (e.g., Biafra in Nigeria), and difficulty building cohesive governance.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-indp-fc-3', 'How did Cold War dynamics challenge new states?', 'Superpowers competed for influence in newly independent states, funding rival factions, sometimes supporting authoritarian rulers, and creating proxy conflicts that destabilised new nations.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-indp-fc-3', 'What social challenges emerged after independence?', 'Addressing inequality (land reform, education, healthcare), managing expectations of populations who expected rapid improvement, dealing with refugee crises, and overcoming deep social divisions left by colonialism.', 6);
INSERT OR IGNORE INTO history_flashcard_topics (id, label, color, unit, sort_order) VALUES ('hist-p2-indp-fc-4', '4. Responses to Challenges', '#A39B6B', 'P2-INDP', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-indp-fc-4', 'How did India respond to post-independence challenges?', 'Adopted a secular democratic constitution (1950), implemented Five-Year Plans for economic development, pursued non-alignment in Cold War, integrated princely states, and addressed communal tensions through federal structures.', 1);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-indp-fc-4', 'What was the Non-Aligned Movement (NAM)?', 'Founded in 1961, NAM was a group of newly independent states (led by Nehru, Nasser, Tito, Sukarno, Nkrumah) that refused to align with either Cold War superpower bloc, seeking an independent foreign policy path.', 2);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-indp-fc-4', 'How did many African states respond to ethnic divisions?', 'Some adopted one-party states to promote unity (e.g., Nkrumah in Ghana, Nyerere in Tanzania), others adopted federalism (Nigeria), while some experienced military coups as the army stepped in to ''restore order''.', 3);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-indp-fc-4', 'What was Ujamaa in Tanzania?', 'Julius Nyerere''s policy of ''African socialism'' emphasising communal farming, self-reliance, and rural development through villagisation. It aimed to avoid both capitalist exploitation and Soviet-style communism.', 4);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-indp-fc-4', 'How did states address economic challenges?', 'Nationalisation of key industries, land reform, import-substitution industrialisation, seeking foreign aid, joining regional economic organisations, and diversifying exports. Success varied significantly.', 5);
INSERT INTO history_flashcards (topic_id, term, definition, sort_order) VALUES ('hist-p2-indp-fc-4', 'What constitutional arrangements were adopted?', 'Varied widely: India chose parliamentary democracy; many African states adopted one-party systems; some kept colonial legal frameworks; others created entirely new constitutions. Many faced constitutional crises within the first decade.', 6);

-- MCQ questions
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-362', '1. Origins and Rise of Independence Movements', 'SL/HL', 'P2-INDP', 'Which event directly destabilised Spanish control over its American colonies?', 'The French Revolution (1789)', 'Napoleon''s invasion of Spain (1808)', 'The Congress of Vienna (1815)', 'The American Civil War (1861)', 1, 'See mark scheme for detailed explanation.', 363);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-363', '1. Origins and Rise of Independence Movements', 'SL/HL', 'P2-INDP', 'The Indian National Congress was founded in:', '1857', '1885', '1905', '1919', 1, 'See mark scheme for detailed explanation.', 364);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-364', '1. Origins and Rise of Independence Movements', 'SL/HL', 'P2-INDP', 'Which of the following was NOT a factor in the rise of independence movements?', 'Enlightenment philosophy', 'Mercantilist trade restrictions', 'The Industrial Revolution in the colonies', 'Exclusion of locals from political power', 2, 'See mark scheme for detailed explanation.', 365);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-365', '1. Origins and Rise of Independence Movements', 'SL/HL', 'P2-INDP', 'The Atlantic Charter (1941) was significant for independence movements because it:', 'Granted immediate independence to all colonies', 'Declared the right of peoples to self-government', 'Established the United Nations', 'Created the Non-Aligned Movement', 1, 'See mark scheme for detailed explanation.', 366);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-366', '1. Origins and Rise of Independence Movements', 'SL/HL', 'P2-INDP', 'Which leader issued the Grito de Dolores?', 'Simon Bolivar', 'Jose de San Martin', 'Miguel Hidalgo', 'Bernardo O''Higgins', 2, 'See mark scheme for detailed explanation.', 367);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-367', '2. Methods Used and Reasons for Success', 'SL/HL', 'P2-INDP', 'Gandhi''s Salt March (1930) was an example of:', 'Armed insurrection', 'Civil disobedience', 'Diplomatic negotiation', 'Military coup', 1, 'See mark scheme for detailed explanation.', 368);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-368', '2. Methods Used and Reasons for Success', 'SL/HL', 'P2-INDP', 'UN Resolution 1514 (1960) is significant because it:', 'Created the Non-Aligned Movement', 'Declared colonialism a denial of human rights', 'Imposed sanctions on all colonial powers', 'Granted independence to India', 1, 'See mark scheme for detailed explanation.', 369);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-369', '2. Methods Used and Reasons for Success', 'SL/HL', 'P2-INDP', 'Which of these movements primarily used guerrilla warfare?', 'Indian independence', 'Ghanaian independence', 'Algerian independence (FLN)', 'Canadian Confederation', 2, 'See mark scheme for detailed explanation.', 370);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-370', '2. Methods Used and Reasons for Success', 'SL/HL', 'P2-INDP', 'A key reason for the success of Indian independence was:', 'India defeating Britain in a major battle', 'Post-WWII British economic weakness', 'American military intervention', 'Soviet nuclear threats against Britain', 1, 'See mark scheme for detailed explanation.', 371);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-371', '2. Methods Used and Reasons for Success', 'SL/HL', 'P2-INDP', 'The Mau Mau Uprising took place in:', 'Algeria', 'Vietnam', 'Kenya', 'India', 2, 'See mark scheme for detailed explanation.', 372);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-372', '3. Challenges Faced in the First 10 Years', 'SL/HL', 'P2-INDP', 'Approximately how many people were displaced by the Partition of India?', '1-2 million', '5-7 million', '10-15 million', '25-30 million', 2, 'See mark scheme for detailed explanation.', 373);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-373', '3. Challenges Faced in the First 10 Years', 'SL/HL', 'P2-INDP', 'Which of the following was a key economic challenge for new states?', 'Excessive industrialisation', 'Over-diversified economies', 'Dependence on single export commodities', 'Too much foreign investment', 2, 'See mark scheme for detailed explanation.', 374);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-374', '3. Challenges Faced in the First 10 Years', 'SL/HL', 'P2-INDP', 'The Biafran War (1967-70) in Nigeria was caused primarily by:', 'Cold War proxy conflict', 'Ethnic and regional tensions', 'British military intervention', 'Religious persecution', 1, 'See mark scheme for detailed explanation.', 375);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-375', '3. Challenges Faced in the First 10 Years', 'SL/HL', 'P2-INDP', 'A common political challenge in newly independent states was:', 'Excessive democracy', 'Lack of established state institutions', 'Over-reliance on colonial advisors', 'Too many political parties', 1, 'See mark scheme for detailed explanation.', 376);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-376', '3. Challenges Faced in the First 10 Years', 'SL/HL', 'P2-INDP', 'How did Cold War dynamics affect newly independent states?', 'They were largely ignored by superpowers', 'Superpowers competed for influence, often destabilising them', 'They all joined NATO or the Warsaw Pact', 'The Cold War had no impact on decolonised states', 1, 'See mark scheme for detailed explanation.', 377);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-377', '4. Responses to Challenges', 'SL/HL', 'P2-INDP', 'The Non-Aligned Movement was founded in:', '1945', '1955', '1961', '1975', 2, 'See mark scheme for detailed explanation.', 378);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-378', '4. Responses to Challenges', 'SL/HL', 'P2-INDP', 'Ujamaa was a policy implemented in:', 'India', 'Ghana', 'Tanzania', 'Vietnam', 2, 'See mark scheme for detailed explanation.', 379);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-379', '4. Responses to Challenges', 'SL/HL', 'P2-INDP', 'Which was NOT a common economic response to post-independence challenges?', 'Nationalisation of industries', 'Import-substitution industrialisation', 'Immediate integration into global free trade', 'Five-Year Plans', 2, 'See mark scheme for detailed explanation.', 380);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-380', '4. Responses to Challenges', 'SL/HL', 'P2-INDP', 'Many African leaders adopted one-party states primarily to:', 'Impress Western donors', 'Promote national unity across ethnic lines', 'Copy the Soviet model exactly', 'Punish opposition groups', 1, 'See mark scheme for detailed explanation.', 381);
INSERT OR IGNORE INTO history_mcq_questions (id, category, difficulty, unit, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, sort_order) VALUES ('hist-p2-mcq-381', '4. Responses to Challenges', 'SL/HL', 'P2-INDP', 'India''s response to the challenge of princely states was:', 'Military conquest of all states', 'Allowing complete autonomy', 'Integration through negotiation and the States Reorganisation Act', 'Ignoring the problem', 2, 'See mark scheme for detailed explanation.', 382);

-- Written questions (15 marks)
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-152', '1. Origins and Rise of Independence Movements', 'SL/HL', 'short_answer', 'P2-INDP', 15, 'Examine the role of ideology in the origins of two independence movements, each from a different region.', '• Band 5 (13-15): Detailed, well-structured analysis of ideological factors in two movements from different regions, with consistent comparison and specific evidence.
• Key content may include: Enlightenment ideas (liberty, self-determination, republicanism), nationalism, socialism/Marxism, pan-Africanism, or religious identity.
• Case studies should come from different regions (e.g., Latin America + Asia, or Africa + Europe).
• Examples: Bolivar influenced by Enlightenment/republicanism; Ho Chi Minh influenced by Marxism-Leninism and anti-imperialism; Indian independence shaped by Gandhian philosophy and Hindu-Muslim nationalism.
• Strong answers will evaluate relative importance of ideology vs. other factors (economic, social, external).
• Band 3 (7-9): Narrative or descriptive account with some analysis; may focus on one movement or lack regional comparison.
• Band 1 (1-3): Generalised, vague, or inaccurate with minimal relevant knowledge.', 153);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-153', '1. Origins and Rise of Independence Movements', 'SL/HL', 'short_answer', 'P2-INDP', 15, 'To what extent were economic grievances the most important cause of independence movements?', '• Band 5 (13-15): Balanced, evaluative argument weighing economic factors against other causes (political, ideological, social, external). Uses detailed evidence from two or more movements.
• Economic factors: mercantilist restrictions, heavy taxation, exploitation of resources, exclusion from trade, land ownership issues. Counter-arguments: political exclusion, racial discrimination, ideological awakening, impact of world wars, role of charismatic leaders.
• Must refer to specific movements with detailed examples (e.g., Indian salt tax, Latin American trade monopolies).
• Strong responses offer a clear, well-supported judgement on ''to what extent''.
• Band 3 (7-9): Some analysis but may be descriptive; limited comparison across movements.
• Band 1 (1-3): Little relevant knowledge; generalised claims without supporting evidence.', 154);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-154', '2. Methods Used and Reasons for Success', 'SL/HL', 'short_answer', 'P2-INDP', 15, 'Compare and contrast the methods used by two independence movements, each from a different region.', '• Band 5 (13-15): Systematic comparison of methods (violent vs. non-violent, diplomatic, economic) with detailed evidence from two movements in different regions.
• Must show genuine comparison (not just two separate descriptions). Use linking language: ''similarly'', ''in contrast'', ''whereas''.
• Examples: India (non-violent civil disobedience under Gandhi) vs. Algeria (armed guerrilla warfare under FLN); or Vietnam (Viet Minh guerrilla + political) vs. Ghana (constitutional agitation under Nkrumah).
• Strong answers will explain WHY different methods were chosen (context-dependent) and evaluate which were more effective.
• Band 3 (7-9): Some comparison but may be implicit or narrative-driven; limited evaluation.
• Band 1 (1-3): Vague, generalised, or describes only one movement without comparison.', 155);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-155', '2. Methods Used and Reasons for Success', 'SL/HL', 'short_answer', 'P2-INDP', 15, 'Evaluate the importance of foreign intervention in the success of one independence movement.', '• Band 5 (13-15): Detailed evaluation weighing foreign intervention against domestic factors. Clear judgement on relative importance. Foreign intervention may include: military support, diplomatic recognition, economic aid, Cold War dynamics, UN resolutions, colonial power''s weakness. Domestic factors: quality of leadership, mass mobilisation, economic disruption, guerrilla effectiveness, ideology.
• Case-specific evidence required (e.g., French support for American Revolution; Chinese/Soviet support for Viet Minh; British support for Latin American independence).
• Band 3 (7-9): Narrative account with some analysis; may not fully evaluate relative importance.
• Band 1 (1-3): Minimal knowledge; no evaluation or judgement offered.', 156);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-156', '3. Challenges Faced in the First 10 Years', 'SL/HL', 'short_answer', 'P2-INDP', 15, 'Examine the political challenges faced in the first 10 years of independence by two states, each from a different region.', '• Band 5 (13-15): Detailed analysis of political challenges with comparison across two states from different regions. Specific evidence and evaluation. Political challenges: constitutional debates, one-party vs. multi-party systems, ethnic/religious divisions, power struggles, military coups, border disputes.
• Examples: India (Hindu-Muslim tensions, integration of princely states, democratic consolidation) vs. Ghana (Nkrumah''s drift to authoritarianism, ethnic tensions, economic mismanagement).
• Or: Vietnam (reunification challenges, communist consolidation) vs. Algeria (Ben Bella vs. Boumediene power struggle, FLN factionalism).
• Strong answers evaluate the severity and interconnection of challenges.
• Band 3 (7-9): Some analysis but may be descriptive; limited comparison.
• Band 1 (1-3): Generalised with minimal specific knowledge.', 157);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-157', '3. Challenges Faced in the First 10 Years', 'SL/HL', 'short_answer', 'P2-INDP', 15, 'To what extent were the challenges faced by newly independent states a result of their colonial past?', '• Band 5 (13-15): Evaluative argument weighing colonial legacy against post-independence decisions and external factors. Detailed evidence from specific case studies. Colonial legacy factors: arbitrary borders, mono-crop economies, weak institutions, racial/ethnic hierarchies, limited education systems, infrastructure gaps. Post-independence factors: leadership choices (corruption, authoritarianism), Cold War pressures, regional conflicts, economic policies.
• Must provide balanced judgement with clear ''to what extent'' evaluation.
• Band 3 (7-9): Some relevant knowledge but limited evaluation or balance.
• Band 1 (1-3): Vague generalisations; no clear argument.', 158);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-158', '4. Responses to Challenges', 'SL/HL', 'short_answer', 'P2-INDP', 15, 'Evaluate the effectiveness of the responses to economic challenges in the first 10 years of two states, each from a different region.', '• Band 5 (13-15): Evaluative comparison of economic responses with detailed evidence. Clear judgement on effectiveness.
• Economic responses may include: nationalisation, land reform, five-year plans, import-substitution, foreign aid, regional cooperation, agricultural policies.
• Examples: India (mixed economy, Five-Year Plans, Green Revolution foundations) vs. Tanzania (Ujamaa, villagisation, nationalisation) or Ghana (industrialisation under Nkrumah, Akosombo Dam).
• Must evaluate effectiveness: growth achieved? inequality addressed? sustainability? foreign dependency?
• Strong answers consider both short-term and long-term outcomes.
• Band 3 (7-9): Some relevant knowledge but limited evaluation or comparison.
• Band 1 (1-3): Vague; minimal specific evidence.', 159);
INSERT OR IGNORE INTO history_written_questions (id, category, difficulty, question_type, unit, marks, question_text, mark_scheme, sort_order) VALUES ('hist-p2-wq-159', '4. Responses to Challenges', 'SL/HL', 'short_answer', 'P2-INDP', 15, 'Discuss the extent to which the adoption of one-party states was an effective response to post-independence challenges in one state.', '• Band 5 (13-15): Detailed analysis of one-party rule as a response, weighing benefits against drawbacks with specific evidence. Arguments for: national unity, rapid decision-making, stability, overcoming ethnic divisions, focused economic planning. Arguments against: suppression of opposition, human rights abuses, corruption, lack of accountability, eventual instability.
• Case studies: Nkrumah''s Ghana (CPP dominance, Preventive Detention Act), Nyerere''s Tanzania (TANU/CCM), Kenyatta''s Kenya (KANU).
• Must offer clear judgement on ''effectiveness''.
• Band 3 (7-9): Narrative with some analysis; may not fully evaluate effectiveness.
• Band 1 (1-3): Generalised claims; no specific case study evidence.', 160);
